INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12001, 1, '📺 8K 초고화질 시네마틱 TV', '', '✨ 거실을 영화관으로 만드는 압도적 몰입감\n💎 AI 업스케일링으로 더 선명한 디테일\n📌 지금 구매 시 프리미엄 사운드바 증정\n▶ 바로가기', '', 190000.00, 950),
(12002, 1, '🧊 4도어 비스포크 냉장고', '', '🎨 내 주방에 딱 맞는 맞춤형 컬러 디자인\n✨ 신선도를 지켜주는 독립 냉각 시스템\n💰 신년 맞이 보상판매 특별 할인 중\n▶ 쇼핑하기', '', 1480000.00, 7400),
(12003, 1, '🧺 AI 그랑데 세탁기+건조기 세트', '', '🤖 세탁부터 건조까지 AI가 알아서 척척\n✨ 살균 스팀으로 유해균 99.9% 제거\n🚀 오늘 주문 시 내일 전문 기사 방문 설치\n▶ 제품 보기', '', 870000.00, 4350),
(12004, 1, '💻 최신형 초경량 노트북 16인치', '', '🚀 압도적인 성능의 최신 프로세서 탑재\n✨ 1kg 초반대 무게로 외출도 가볍게\n🎁 대학생 할인 및 전용 파우치 증정\n▶ 상세 보기', '', 260000.00, 1300),
(12005, 1, '💨 미세먼지 제로! 공기청정기 프리미엄', '', '🍃 360도 강력 흡입으로 실내 공기 정화\n✨ 스마트폰 앱으로 실시간 수치 확인 가능\n🎯 렌탈 서비스 이용 시 월 이용료 할인\n▶ 렌탈 문의', '', 1550000.00, 7750),
(12006, 1, '🧹 로봇청소기 스테이션 풀세트', '', '✨ 먼지 비움부터 걸레 세척까지 완전 자동\n🤖 정밀 센서로 장애물 완벽 회피\n💰 기간 한정 소모품 1년치 무상 제공\n▶ 구매하기', '', 940000.00, 4700),
(12007, 1, '🥘 요리가 쉬워지는 대용량 에어프라이어', '', '🔥 직관적인 터치 패널과 넉넉한 10L 바스켓\n✨ 기름 없이 바삭한 겉바속촉 요리 완성\n📌 전용 레시피북 선착순 증정 중\n▶ 더 보기', '', 330000.00, 1650),
(12008, 1, '🧊 급속 냉동 가능한 스탠드 김치냉장고', '', '🥬 사계절 내내 아삭한 김치 맛 유지\n✨ 식재료별 맞춤 보관 모드 탑재\n💰 에너지 효율 1등급 환급 대상 제품\n▶ 쇼핑하기', '', 1620000.00, 8100),
(12009, 1, '☕ 홈카페의 완성, 전자동 에스프레소 머신', '', '✨ 원두 그라인딩부터 추출까지 버튼 하나로\n💎 벨벳 같은 밀크 폼 스팀 기능 포함\n📌 구매 시 프리미엄 원두 1kg 증정\n▶ 구경하기', '', 1010000.00, 5050),
(12010, 1, '🔋 무선 청소기 하이엔드 에디션', '', '🔥 초강력 흡입력과 최장 60분 연속 사용\n✨ 가벼운 무게로 손목 부담 제로\n💰 배터리 1+1 추가 증정 이벤트\n▶ 상세 보기', '', 400000.00, 2000),
(12011, 1, '🥤 얼음 나오는 정수기 렌탈 케어', '', '❄️ 단단하고 투명한 얼음이 쏟아지는 행복\n✨ 6개월마다 전문 코디 방문 살균 케어\n🎁 초기 등록비 및 설치비 전액 면제\n▶ 상담 신청', '', 1690000.00, 8450),
(12012, 1, '🥘 인덕션 3구 하이브리드 전기레인지', '', '🔥 강력한 화력과 화상 위험 없는 안전 설계\n✨ 청소가 간편한 프리미엄 글라스 상판\n💰 기존 가스레인지 철거 지원 서비스\n▶ 확인하기', '', 1080000.00, 5400),
(12013, 1, '🌬️ 초미세 풍량 조절 BLDC 선풍기', '', '🍃 아기 바람부터 강풍까지 24단계 조절\n✨ 저소음 설계로 밤새도록 조용하게\n📌 리모컨 포함 화이트 감성 디자인\n▶ 구매하기', '', 470000.00, 2350),
(12014, 1, '📺 거실의 품격, OLED 벽걸이 TV', '', '✨ 백라이트 없는 완벽한 블랙의 구현\n💎 초슬림 베젤로 벽과 하나 되는 인테리어\n💰 프리미엄 설치 서비스 포함가\n▶ 제품 보기', '', 1760000.00, 8800),
(12015, 1, '🍞 겉바속촉 스팀 토스터기', '', '✨ 죽은 빵도 살려내는 기적의 스팀 기술\n🥐 크로와상부터 바게트까지 맞춤 조리\n📌 감성 가전 1위 제품을 만나보세요\n▶ 쇼핑하기', '', 1150000.00, 5750),
(12016, 1, '🍷 와인 애호가 필수템, 와인 셀러', '', '🍇 최적의 온도와 습도로 와인의 맛 보존\n✨ 무진동 저소음 설계로 안심 보관\n💰 12구/24구 모델 할인 프로모션\n▶ 구경하기', '', 540000.00, 2700),
(12017, 1, '🧖 신개념 의류관리기 스타일러', '', '✨ 매일 입는 정장, 코트 미세먼지 살균\n💎 바지 칼주름 관리까지 한 번에\n📌 렌탈 월 요금 2만원대 특가 진행 중\n▶ 상세 보기', '', 1830000.00, 9150),
(12018, 1, '🧼 6인용 식기세척기 카운터탑', '', '✨ 좁은 주방에도 쏙! 강력한 고온 살균 세척\n🔥 자동 문 열림 건조로 물때 걱정 제로\n💰 런칭 기념 전용 세제 세트 증정\n▶ 구매하기', '', 1220000.00, 6100),
(12019, 1, '💨 초강력 헤어드라이어 프로', '', '✨ 모발 손상 최소화, 음이온 케어 기술\n🔥 바쁜 아침 건조 시간을 절반으로 단축\n🎁 전용 노즐 3종 및 거치대 포함\n▶ 더 보기', '', 610000.00, 3050),
(12020, 1, '🎮 게이밍 모니터 144Hz 커브드', '', '🚀 승률을 높이는 빠른 응답 속도\n✨ 몰입감을 극대화하는 곡률 디자인\n💰 한정 수량 게이밍 마우스 증정\n▶ 바로가기', '', 1900000.00, 9500),
(12021, 1, '🧊 휴대용 미니 냉장고 10L', '', '🚗 캠핑이나 차량에서 즐기는 시원함\n✨ 화장품 냉장고로도 활용 만점\n💰 기간 한정 배송비 무료 혜택\n▶ 쇼핑하기', '', 1290000.00, 6450),
(12022, 1, '🔊 블루투스 스피커 하이파이 사운드', '', '✨ 인테리어를 완성하는 레트로 디자인\n💎 깊은 베이스와 선명한 고음의 조화\n📌 오늘만 20% 깜짝 할인 쿠폰 발급\n▶ 구경하기', '', 680000.00, 3400),
(12023, 1, '🥩 멀티 전기 그릴 홈캠핑용', '', '🔥 연기 걱정 없이 즐기는 실내 바비큐\n✨ 기름 빠지는 구조로 담백한 요리 가능\n💰 주말 한정 구이용 집게 세트 증정\n▶ 제품 보기', '', 1970000.00, 9850),
(12024, 1, '🧥 보풀 제거기 전문가용 무선', '', '✨ 오래된 니트도 새 옷처럼 깔끔하게\n💎 강력한 6중 칼날과 3단계 속도 조절\n📌 가방에 쏙 들어가는 콤팩트 사이즈\n▶ 구매하기', '', 1360000.00, 6800),
(12025, 1, '💡 스마트 LED 조명 스탠드', '', '✨ 눈이 편안한 시력 보호 기술 탑재\n📱 앱 연동으로 색온도 및 밝기 조절\n💰 수험생 응원 특별 할인 판매 중\n▶ 상세 보기', '', 750000.00, 3750),
(12026, 1, '🍚 당질 제한 건강 밥솥 6인용', '', '✨ 밥맛은 그대로, 탄수화물만 쏙 뺐습니다\n💎 다이어터와 당뇨 환자 필수 가전\n📌 화이트/블랙 감성 디자인 선택\n▶ 쇼핑하기', '', 140000.00, 700),
(12027, 1, '🌬️ 초강력 공기 순환기 서큘레이터', '', '🍃 실내 공기를 빠르게 순환시키는 파워\n✨ 에어컨과 함께 쓰면 냉방 효과 극대화\n💰 1+1 세트 구매 시 추가 할인\n▶ 더 보기', '', 1430000.00, 7150),
(12028, 1, '🧳 휴대용 스팀 다리미 핸디형', '', '✨ 예열 30초! 바쁜 외출 전 빠르게 살균\n💎 수직/수평 다림질 모두 가능한 설계\n📌 여행 가방 필수템, 지금 득템하세요\n▶ 구매하기', '', 820000.00, 4100),
(12029, 1, '🧖 족욕기 원적외선 건식형', '', '✨ 물 없이 즐기는 간편한 하반신 힐링\n💎 부모님 효도 선물 1순위 건강 가전\n💰 가정의 달 선 결제 할인 프로모션\n▶ 상세 보기', '', 210000.00, 1050),
(12030, 1, '📸 미러리스 카메라 초보자 패키지', '', '✨ 가벼운 무게와 강력한 오토포커스\n💎 일상을 영화처럼 기록하는 4K 영상\n🎁 SD카드 및 가방 풀패키지 포함\n▶ 구경하기', '', 1500000.00, 7500),
(12031, 1, '💧 대용량 초음파 가습기 4L', '', '✨ 밤새도록 촉촉하게, 무드등 기능 포함\n💎 상부 급수 방식으로 편리한 세척\n💰 겨울 시즌 마감 파격 세일 진행 중\n▶ 쇼핑하기', '', 890000.00, 4450),
(12032, 1, '🥗 저속 압착 주서기(휴롬)', '', '🍎 과일 채소 영양소 파괴 없는 리얼 착즙\n✨ 세척이 쉬운 심플한 내부 구조\n📌 건강한 아침 습관을 시작하세요\n▶ 제품 보기', '', 280000.00, 1400),
(12033, 1, '⌨️ 무선 기계식 키보드 저소음', '', '✨ 쫀득한 타건감과 조용한 사무 환경\n💎 멀티 페어링으로 기기 3대 연결 가능\n💰 런칭 기념 손목 받침대 사은품\n▶ 구매하기', '', 1570000.00, 7850),
(12034, 1, '🧴 초음파 안경 세척기 가정용', '', '✨ 보이지 않는 틈새 오염까지 완벽 제거\n💎 액세서리, 면도날도 세척 가능\n📌 깔끔한 당신을 위한 스마트한 습관\n▶ 더 보기', '', 960000.00, 4800),
(12035, 1, '⌚ 스마트워치 스포츠 에디션', '', '🏃 24시간 건강 모니터링 및 운동 기록\n✨ 강력한 방수 기능과 한 달 유지 배터리\n💰 기간 한정 스트랩 2종 추가 증정\n▶ 바로가기', '', 350000.00, 1750),
(12036, 1, '🍲 멀티 압력 쿠커(인스턴트팟)', '', '🔥 찜, 국, 요거트까지 버튼 하나로 완성\n✨ 요리 시간을 절반으로 줄여주는 마법\n📌 100가지 레시피북 포함 패키지\n▶ 쇼핑하기', '', 1640000.00, 8200),
(12037, 1, '🌬️ 에어 서큘레이터 타워형', '', '🍃 슬림한 디자인으로 좁은 공간도 OK\n✨ 상하좌우 자동 회전으로 사각지대 제로\n💰 주말 한정 무료 배송 및 반품 가능\n▶ 제품 보기', '', 1030000.00, 5150),
(12038, 1, '🧊 가정용 제빙기 대용량 일 15kg', '', '❄️ 홈바, 캠핑장 어디서나 얼음 걱정 끝\n✨ 7분마다 쏟아지는 깨끗한 얼음\n💰 지금 사면 전용 보관 가방 증정\n▶ 구매하기', '', 420000.00, 2100),
(12039, 1, '🚿 스마트 비데 직수형 살균', '', '✨ 풀 스테인리스 노즐과 전해수 살균\n💎 전기료 아끼는 절전 모드 탑재\n🎁 자가 설치 키트 포함 특가 판매\n▶ 상세 보기', '', 1710000.00, 8550),
(12040, 1, '🧇 3in1 와플 메이커 샌드위치기', '', '✨ 플레이트 교체로 와플부터 크로플까지\n💎 눌어붙지 않는 논스틱 코팅 상판\n📌 아이들 간식 요리사로 변신하세요\n▶ 쇼핑하기', '', 1100000.00, 5500),
(12041, 1, '🔌 스마트 멀티탭 앱 제어형', '', '✨ 밖에서도 가전제품 전원 오프 가능\n💎 대기 전력 차단으로 전기료 절감\n💰 3구/5구 모델 선택 및 할인 중\n▶ 구매하기', '', 490000.00, 2450),
(12042, 1, '🏋️ 진동 마사지건 전문가용', '', '✨ 운동 후 근육 뭉침 시원하게 해결\n💎 30단계 강도 조절과 저소음 모터\n🎁 마사지 헤드 6종 풀세트 증정\n▶ 제품 보기', '', 1780000.00, 8900),
(12043, 1, '🥩 가정용 고기 숙성고 미니', '', '🥩 집에서도 즐기는 프리미엄 드라이 에이징\n✨ 최적의 온도와 습도 자동 제어\n💰 고기 매니아를 위한 한정 수량 출시\n▶ 구경하기', '', 1170000.00, 5850),
(12044, 1, '🧥 전자동 신발 세탁기 가정용', '', '👟 운동화 세탁, 이제 손대지 말고 돌리세요\n✨ 특수 브러쉬로 찌든 때까지 깔끔하게\n📌 1인 가구 필수템, 삶의 질 상승 가전\n▶ 구매하기', '', 560000.00, 2800),
(12045, 1, '💨 미니 공기청정기 탁상용', '', '🍃 내 책상 위 작은 숲, 헤파필터 탑재\n✨ USB 전원 방식으로 어디서나 사용\n💰 1+1 묶음 구매 시 반값 할인\n▶ 쇼핑하기', '', 1850000.00, 9250),
(12046, 1, '🥛 두유 제조기 죽 마스터기', '', '✨ 불릴 필요 없이 콩만 넣으면 끝\n💎 건강한 수제 두유를 아침마다 신선하게\n📌 구매 시 국내산 백태 1kg 증정\n▶ 제품 보기', '', 1240000.00, 6200),
(12047, 1, '🧖 저소음 구강세정기 무선형', '', '✨ 칫솔이 닿지 않는 곳까지 강력 세정\n💎 잇몸 건강을 위한 5가지 수압 모드\n💰 런칭 기념 팁 4종 세트 추가 증정\n▶ 상세 보기', '', 630000.00, 3150),
(12048, 1, '🧴 칫솔 살균기 UV-C LED 거치형', '', '✨ 세균 번식 99% 억제, 자동 살균 시스템\n💎 깔끔한 욕실 인테리어를 위한 디자인\n📌 무타공 설치로 누구나 간편하게\n▶ 구매하기', '', 1920000.00, 9600),
(12049, 1, '🌡️ 비접촉 적외선 체온계 스마트', '', '✨ 1초 만에 정확한 측정, 메모리 기능\n💎 아기 체온부터 사물 온도까지 측정\n💰 가정 상비 가전 특별 기획전 진행\n▶ 쇼핑하기', '', 1310000.00, 6550),
(12050, 1, '🔋 급속 무선 충전기 3in1 스테이션', '', '📱 스마트폰, 워치, 이어폰을 동시에 충전\n✨ 깔끔한 데스크테리어를 위한 필수템\n💰 런칭 기념 케이블 정리기 세트 증정\n▶ 제품 보기', '', 700000.00, 3500);
