INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12051, 1, '🌡️ 맞춤 온도의 마법, 분유 포트 프리미엄', '', '✨ 1도 단위 정밀 온도 조절과 24시간 보온\n💎 밤중 수유도 당황하지 않고 간편하게\n📌 의료용 스테인리스 소재로 안심 사용\n▶ 바로가기', '', 1990000.00, 9950),
(12052, 1, '🧵 수선이 쉬워지는 미니 재봉틀', '', '✨ 초보자도 5분 만에 배우는 간편한 조작\n💎 바지 밑단부터 인형 옷 만들기까지 OK\n💰 전용 실 세트 및 바늘 추가 증정\n▶ 쇼핑하기', '', 1380000.00, 6900),
(12053, 1, '🔊 사운드바 홈시어터 2.1채널', '', '✨ 거실을 가득 채우는 웅장한 중저음의 매력\n💎 무선 우퍼로 선 정리 없이 깔끔한 설치\n🚀 오늘 주문 시 전문 기사 내일 방문\n▶ 제품 보기', '', 770000.00, 3850),
(12054, 1, '💻 고성능 일체형 PC 27인치', '', '🚀 모니터와 본체가 하나로! 데스크테리어 완성\n✨ 인텔 최신 프로세서로 끊김 없는 작업\n🎁 로지텍 무선 키보드 마우스 세트 증정\n▶ 상세 보기', '', 160000.00, 800),
(12055, 1, '💨 초강력 의류 건조기 9kg', '', '🍃 좁은 세탁실에도 쏙 들어가는 콤팩트 사이즈\n✨ 저온 제습 건조로 옷감 손상 최소화\n🎯 렌탈 가입 시 초기 비용 0원 혜택\n▶ 렌탈 문의', '', 1450000.00, 7250),
(12056, 1, '🧹 틈새 청소 전문! 핸디 무선 청소기', '', '✨ 소파 사이, 자동차 시트 먼지 완벽 흡입\n🤖 가벼운 무게와 강력한 BLDC 모터 탑재\n💰 필터 2개 추가 포함 기획 세트\n▶ 구매하기', '', 840000.00, 4200),
(12057, 1, '🥘 디지털 멀티 찜기 3단', '', '🔥 영양소 파괴 없이 즐기는 건강한 요리\n✨ 타이머 기능으로 태울 걱정 없이 안심\n📌 다이어터 식단 준비 필수 아이템\n▶ 더 보기', '', 230000.00, 1150),
(12058, 1, '🧊 서랍형 냉동고 150L', '', '🥬 냉장고 용량 부족? 서랍형으로 깔끔 정리\n✨ 성에 제거가 필요 없는 간접 냉각 방식\n💰 에너지 효율 등급 우수 가전 환급 대상\n▶ 쇼핑하기', '', 1520000.00, 7600),
(12059, 1, '☕ 캡슐 커피 머신 미니멀 에디션', '', '✨ 버튼 하나로 즐기는 전 세계 프리미엄 커피\n💎 어디에나 잘 어울리는 슬림한 디자인\n📌 시식용 웰컴 캡슐 12종 무료 증정\n▶ 구경하기', '', 910000.00, 4550),
(12060, 1, '🔋 급속 보조배터리 20,000mAh', '', '🔥 노트북 충전도 가능한 고출력 PD 지원\n✨ 잔량 확인이 쉬운 디지털 디스플레이\n💰 2개 구매 시 20% 추가 할인 이벤트\n▶ 상세 보기', '', 300000.00, 1500),
(12061, 1, '🥤 올스테인리스 냉온 정수기', '', '❄️ 물이 닿는 모든 곳이 스테인리스라 안심\n✨ 필터 셀프 교체형으로 유지비 절감\n🎁 신규 가입 시 신세계 상품권 증정\n▶ 상담 신청', '', 1590000.00, 7950),
(12062, 1, '🥘 와이드 전기 그릴 팬 70cm', '', '🔥 명절 전 부치기부터 고기 파티까지 한 번에\n✨ 눌어붙지 않는 강력한 티타늄 코팅\n💰 기름받이 및 보관 가방 세트 포함\n▶ 확인하기', '', 980000.00, 4900),
(12063, 1, '🌬️ 스마트 리모컨 벽걸이 선풍기', '', '🍃 공간 차지는 줄이고 시원함은 그대로\n✨ 7엽 날개로 부드럽고 멀리 가는 바람\n📌 깔끔한 화이트톤 디자인의 가성비 템\n▶ 구매하기', '', 370000.00, 1850),
(12064, 1, '📺 차량용 모니터 15인치 스마트형', '', '✨ 넷플릭스, 유튜브 시청 가능한 차량 가전\n💎 장거리 여행 시 아이들의 최고의 친구\n💰 설치비 지원 및 시가잭 케이블 증정\n▶ 제품 보기', '', 1660000.00, 8300),
(12065, 1, '🍞 샌드위치 메이커 싱글형', '', '✨ 바쁜 아침, 3분 만에 완성되는 토스트\n🥐 플레이트 분리 세척으로 위생적인 관리\n📌 1인 가구 자취생 추천 선물 1위\n▶ 쇼핑하기', '', 1050000.00, 5250),
(12066, 1, '🍷 프리미엄 빌트인 와인 냉장고', '', '🍇 가구 속에 쏙! 인테리어와 수납을 동시에\n✨ UV 차단 유리로 와인의 변질 방지\n💰 전문 기사 방문 무료 설치 서비스\n▶ 구경하기', '', 440000.00, 2200),
(12067, 1, '🧖 신발 관리기 슈케어 가전', '', '✨ 눅눅한 운동화 살균부터 냄새 제거까지\n💎 비 오는 날 외출 후 필수 코스\n📌 렌탈 이용 시 신발 탈취제 매달 배송\n▶ 상세 보기', '', 1730000.00, 8650),
(12068, 1, '🧼 업소용 대용량 식기세척기', '', '✨ 단 60초 만에 끝나는 초고속 세척 시스템\n🔥 강력한 고압 분사로 찌든 때 완벽 제거\n💰 창업 지원 특별 할부 프로그램 운영 중\n▶ 구매하기', '', 1120000.00, 5600),
(12069, 1, '💨 헤어 볼륨 스타일러 5in1', '', '✨ 드라이와 스타일링을 동시에 하는 마법\n🔥 자동 회전 브러쉬로 손쉬운 웨이브 연출\n🎁 전용 보관 케이스 및 헤드 5종 포함\n▶ 더 보기', '', 510000.00, 2550),
(12070, 1, '🎮 고사양 게이밍 데스크탑 RTX 4070', '', '🚀 모든 게임을 풀옵션으로 즐기는 괴물 성능\n✨ 화려한 RGB 튜닝 케이스 기본 적용\n💰 오늘 주문 시 게이밍 장패드 무상 증정\n▶ 바로가기', '', 1800000.00, 9000),
(12071, 1, '🧊 미니 화장품 냉장고 6L', '', '🚗 신선한 화장품 사용을 위한 스마트 가전\n✨ 저소음 설계로 침대 옆에 두어도 안심\n💰 여대생 선물용 핑크/민트 컬러 입고\n▶ 쇼핑하기', '', 1190000.00, 5950),
(12072, 1, '🔊 빈티지 감성 턴테이블 스피커', '', '✨ LP판의 아날로그 감성과 블루투스의 편리함\n💎 인테리어 소품으로도 가치 있는 디자인\n📌 입문자용 LP판 1장 랜덤 사은품\n▶ 구경하기', '', 580000.00, 2900),
(12073, 1, '🥩 전기 찜질기 대형 사이즈', '', '🔥 어깨부터 허리까지 따뜻하게 감싸주는 온열\n✨ 극세사 소재로 포근하고 부드러운 촉감\n💰 효도 선물용 고급 패키지 구성\n▶ 제품 보기', '', 1870000.00, 9350),
(12074, 1, '🧥 스마트 구강 세정기 가정용', '', '✨ 치과 가기 전 필수! 강력한 물줄기 세정\n💎 잇몸이 약한 분들을 위한 소프트 모드\n📌 충전식 무선 타입으로 휴대가 간편함\n▶ 구매하기', '', 1260000.00, 6300),
(12075, 1, '💡 인공지능 스마트 홈 조명 세트', '', '✨ 음성으로 끄고 켜는 편리한 스마트 라이프\n📱 1,600만 가지 컬러로 분위기 전환\n💰 설치 가이드 및 허브 포함 패키지 특가\n▶ 상세 보기', '', 650000.00, 3250),
(12076, 1, '🍚 1인용 미니 밥솥 캠핑용', '', '✨ 갓 지은 밥맛을 야외에서도 그대로\n💎 콤팩트한 사이즈와 낮은 소비 전력\n📌 주말 캠핑족을 위한 필수 가전 아이템\n▶ 쇼핑하기', '', 1940000.00, 9700),
(12077, 1, '🌬️ 초고속 에어 서큘레이터 프로', '', '🍃 20m 이상 멀리 뻗어나가는 강력한 직진풍\n✨ 상하좌우 입체 회전으로 빠른 환기\n💰 2대 구매 시 거실/안방 동시 사용 할인\n▶ 더 보기', '', 1330000.00, 6650),
(12078, 1, '🧳 여행용 미니 전기 포트 0.5L', '', '✨ 접이식 실리콘 소재로 캐리어 부피 최소화\n💎 전 세계 전압 호환으로 해외 여행 필수템\n📌 위생적인 스테인리스 바닥 설계\n▶ 구매하기', '', 720000.00, 3600),
(12079, 1, '🧖 파라핀 베스 손 전용 찜질기', '', '✨ 거칠어진 손과 관절을 위한 집중 케어\n💎 전문 샵 수준의 고온 파라핀 팩 효과\n💰 전용 왁스 6개 포함 런칭 기획전\n▶ 상세 보기', '', 110000.00, 550),
(12080, 1, '📸 폴라로이드 즉석 카메라 세트', '', '✨ 찍는 순간 인화되는 아날로그의 낭만\n💎 자동 노출 조절로 누구나 예쁜 사진 촬영\n🎁 전용 가방 및 필름 20매 증정 패키지\n▶ 구경하기', '', 1400000.00, 7000),
(12081, 1, '💧 미니 제습기 원룸용 1L', '', '✨ 드레스룸, 화장실 습기를 싹 잡아줍니다\n💎 펠티어 방식으로 조용하고 전기료 저렴\n💰 여름 장마철 대비 얼리버드 파격 세일\n▶ 쇼핑하기', '', 790000.00, 3950),
(12082, 1, '🥗 요구르트 & 청국장 제조기', '', '🍎 인공 첨가물 없는 수제 유산균 간식\n✨ 온도와 시간만 설정하면 자동으로 완성\n📌 가족 건강을 위한 친환경 가전의 시작\n▶ 제품 보기', '', 180000.00, 900),
(12083, 1, '⌨️ 블루투스 접이식 키보드', '', '✨ 태블릿, 스마트폰 타이핑을 노트북처럼\n💎 가방에 쏙 들어가는 초경량 폴딩 디자인\n💰 비즈니스맨 필수 추천템 기획전\n▶ 구매하기', '', 1470000.00, 7350),
(12084, 1, '🧴 초음파 클리너 귀금속용', '', '✨ 빛바랜 반지와 시계를 새것처럼 광택\n💎 강력한 미세 진동으로 단백질 오염 제거\n📌 액세서리를 사랑하는 분들의 필수품\n▶ 더 보기', '', 860000.00, 4300),
(12085, 1, '⌚ 러닝 전용 GPS 스마트워치', '', '🏃 정확한 경로 추적과 심박수 정밀 분석\n✨ 장시간 달리기에도 끄떡없는 배터리 수명\n💰 런닝화 구매 고객 추가 10% 할인\n▶ 바로가기', '', 250000.00, 1250),
(12086, 1, '🍲 멀티 전기 전골 냄비 5L', '', '🔥 샤브샤브부터 부대찌개까지 식탁에서 바로\n✨ 분리형 용기로 세척이 너무나 간편해요\n📌 집들이 선물로 가장 인기 있는 모델\n▶ 쇼핑하기', '', 1540000.00, 7700),
(12087, 1, '🌬️ 냉풍기 이동식 에어쿨러', '', '🍃 물과 얼음팩으로 에어컨처럼 시원한 바람\n✨ 낮은 전력 소모로 하루 종일 틀어도 안심\n💰 지금 사면 전용 얼음팩 4개 무상 제공\n▶ 제품 보기', '', 930000.00, 4650),
(12088, 1, '🧊 업소용 제빙기 일 50kg', '', '❄️ 카페 창업의 핵심! 멈추지 않는 얼음 생산\n✨ 소음은 줄이고 생산 효율은 높였습니다\n💰 렌탈 및 할부 구매 시 소모품 관리 무료\n▶ 구매하기', '', 320000.00, 1600),
(12089, 1, '🚿 자동 거품 비누 디스펜서', '', '✨ 손대지 않아도 센서가 인식하여 거품 퐁퐁\n💎 위생적인 손 씻기 습관을 길러줍니다\n🎁 1+1 구성으로 욕실과 주방 한 번에 설치\n▶ 상세 보기', '', 1610000.00, 8050),
(12090, 1, ' waffle 붕어빵 메이커 가정용', '', '✨ 집에서 즐기는 바삭한 붕어빵과 와플\n💎 눌어붙지 않는 코팅판으로 뒤집기도 쉬움\n📌 겨울철 홈파티 간식 제조기 강력 추천\n▶ 쇼핑하기', '', 1000000.00, 5000),
(12091, 1, '🔌 전력 측정 스마트 플러그', '', '✨ 실시간 전력 사용량 확인 및 대기전력 차단\n💎 과부하 방지 기능으로 화재 예방까지\n💰 3개 세트 구매 시 추가 할인 혜택\n▶ 구매하기', '', 390000.00, 1950),
(12092, 1, '🏋️ 저주파 마사지기 패치형', '', '✨ 뻐근한 목과 어깨, 근육에 직접 부착\n💎 작지만 강력한 EMS 자극으로 피로 해소\n🎁 교체용 젤 패드 10매 추가 증정 중\n▶ 제품 보기', '', 1680000.00, 8400),
(12093, 1, '🥩 가스식 휴대용 버너(구이바다)', '', '🥩 구이, 전골, 꼬치구이까지 하나로 끝\n✨ 캠핑 고수들의 필수 소장 아이템\n💰 전용 하드 케이스 포함 패키지 판매\n▶ 구경하기', '', 1070000.00, 5350),
(12094, 1, '🧥 진드기 제거 침구 청소기', '', '👟 UV 살균과 진동 펀치로 보이지 않는 먼지까지\n✨ 아토피, 알레르기 걱정 없는 쾌적한 잠자리\n📌 반려동물 키우는 집엔 필수 가전입니다\n▶ 구매하기', '', 460000.00, 2300),
(12095, 1, '💨 도어형 공기청정기 슬림형', '', '🍃 문 뒤나 벽면에 밀착 가능한 초슬림 설계\n✨ 공간 효율은 높이고 공기는 맑게 정화\n💰 런칭 기념 필터 1년치 무상 제공\n▶ 쇼핑하기', '', 1750000.00, 8750),
(12096, 1, '🥛 스마트 우유 거품기 전동식', '', '✨ 카페 라떼, 카푸치노를 위한 완벽한 거품\n💎 따뜻한/차가운 거품 모두 가능합니다\n📌 홈카페 퀄리티를 한 단계 높여보세요\n▶ 제품 보기', '', 1140000.00, 5700),
(12097, 1, '🧖 아쿠아 필링기 갈바닉 가정용', '', '✨ 모공 속 피지 제거와 영양 흡수를 동시에\n💎 에스테틱 샵의 관리를 집에서 간편하게\n💰 런칭 특가 및 전용 앰플 샘플 증정\n▶ 상세 보기', '', 530000.00, 2650),
(12098, 1, '🧴 렌즈 세척기 자동 회전식', '', '✨ 단 30초 만에 렌즈의 단백질 오염 제거\n💎 소중한 내 눈을 위한 건강한 습관\n📌 콤팩트한 사이즈로 파우치에 쏙 들어감\n▶ 구매하기', '', 1820000.00, 9100),
(12099, 1, '🌡️ 냉온 열 찜질 눈 마사지기', '', '✨ 피로한 눈을 위한 온열과 진동 케어\n💎 블루투스 음악 기능으로 더 깊은 휴식\n💰 수험생/직장인 선물용 주문 폭주 중\n▶ 쇼핑하기', '', 1210000.00, 6050),
(12100, 1, '🔋 태양광 충전기 아웃도어용', '', '📱 전기 없는 곳에서도 햇빛만 있으면 충전\n✨ 등산, 낚시, 캠핑 시 비상용으로 최고\n💰 접이식 디자인으로 휴대성 극대화\n▶ 제품 보기', '', 600000.00, 3000);
