INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12101, 1, '📺 거실의 예술, 액자형 프레임 TV', '', '✨ 꺼져 있을 땐 명화가 흐르는 인테리어 가전\n💎 주변 빛에 반응하는 조도 센서로 완벽한 질감\n📌 우리 집 거실을 갤러리로 바꿔보세요\n▶ 바로가기', '', 1890000.00, 9450),
(12102, 1, '🧊 비스포크 김치플러스 3도어', '', '🎨 주방 인테리어에 맞춘 감각적인 패널 디자인\n✨ 0.3도 정밀 정온 기술로 아삭한 김치 맛\n💰 구형 김치냉장고 반납 시 보상 혜택\n▶ 쇼핑하기', '', 1280000.00, 6400),
(12103, 1, '🧺 올인원 세탁건조기 스페이스 세이브', '', '🤖 세탁 후 바로 건조까지, 빨래 옮기지 마세요\n✨ 좁은 베란다에도 최적화된 슬림 사이즈\n🚀 수도권 지역 당일 배송 및 설치 가능\n▶ 제품 보기', '', 670000.00, 3350),
(12104, 1, '💻 게이밍 노트북 리전 프로 16인치', '', '🚀 최신 그래픽카드 탑재로 압도적 프레임 유지\n✨ 냉각 성능 극대화로 발열 걱정 제로\n🎁 전용 백팩 및 게이밍 마우스 증정\n▶ 상세 보기', '', 1960000.00, 9800),
(12105, 1, '💨 헤파 13등급 공기청정기 거실형', '', '🍃 초미세먼지 99.9% 제거, 펫 전용 모드 탑재\n✨ 공기질 상태를 4단계 컬러로 직관적 확인\n🎯 렌탈 가입 시 필터 정기 배송 서비스\n▶ 렌탈 문의', '', 1350000.00, 6750),
(12106, 1, '🧹 자가 세척 로봇청소기 스테이션', '', '✨ 먼지 비움부터 걸레 건조까지 한 번에\n🤖 라이다 센서로 사각지대 없는 완벽 청소\n💰 기간 한정 소모품 패키지 무료 증정\n▶ 구매하기', '', 740000.00, 3700),
(12107, 1, '🥘 스테인리스 에어프라이어 오븐형 15L', '', '🔥 로티세리 기능으로 통닭구이까지 완벽하게\n✨ 올 스테인리스 소재로 유해물질 걱정 끝\n📌 구매 시 조리용 실리콘 장갑 증정\n▶ 더 보기', '', 130000.00, 650),
(12108, 1, '🧊 와이드 슬림 냉장고 200L', '', '🥬 1인 가구 및 자취생을 위한 최적의 공간 활용\n✨ 도어 포켓 강화로 음료 수납이 넉넉함\n💰 에너지 소모 효율 1등급으로 전기료 절감\n▶ 쇼핑하기', '', 1420000.00, 7100),
(12109, 1, '☕ 콜드브루 메이커 홈카페 에디션', '', '✨ 3시간 만에 완성되는 진한 콜드브루의 풍미\n💎 세련된 유리 디자인으로 인테리어 효과까지\n📌 원두 시음 패키지 선착순 증정 중\n▶ 구경하기', '', 810000.00, 4050),
(12110, 1, '🔋 무선 핸디 청소기 터보 맥스', '', '🔥 작지만 강력한 흡입력, 차량용으로도 제격\n✨ 물세척 가능한 반영구 필터 시스템\n💰 1+1 특별 할인으로 거실/차량 동시에\n▶ 상세 보기', '', 200000.00, 1000),
(12111, 1, '🥤 스스로 살균 직수 정수기', '', '❄️ 2시간마다 코크 살균으로 위생 걱정 제로\n✨ 한 뼘 사이즈로 좁은 싱크대도 문제없음\n🎁 신규 렌탈 고객 대상 상품권 증정\n▶ 상담 신청', '', 1490000.00, 7450),
(12112, 1, '🥘 테이블 인덕션 1구 휴대용', '', '🔥 식탁 위에서 바로 요리하며 즐기는 행복\n✨ 세라믹 글라스로 오염 방지 및 간편 세척\n💰 전용 보관 하드 케이스 무료 포함\n▶ 확인하기', '', 880000.00, 4400),
(12113, 1, '🌬️ 무소음 날개 없는 선풍기', '', '🍃 아이와 반려동물에게 안전한 송풍 설계\n✨ 모던한 디자인으로 거실 분위기 업그레이드\n📌 12단계 세밀한 풍량 조절 리모컨 포함\n▶ 구매하기', '', 270000.00, 1350),
(12114, 1, '📺 스마트 빔 프로젝터 4K 해상도', '', '✨ 우리 집 벽면이 150인치 대형 스크린으로\n💎 오토 키스톤 기능으로 초점 맞추기도 간편\n💰 전용 삼각대 및 스크린 패키지 할인\n▶ 제품 보기', '', 1560000.00, 7800),
(12115, 1, '🍞 4구 팝업 토스터기 패밀리형', '', '✨ 온 가족 아침을 한 번에! 굽기 조절 7단계\n🥐 해동 및 재가열 모드로 죽은 빵 살리기\n📌 감성적인 파스텔 컬러 3종 출시\n▶ 쇼핑하기', '', 950000.00, 4750),
(12116, 1, '🍷 프리미엄 미니 와인셀러 8구', '', '🍇 입문자를 위한 콤팩트한 와인 보관 가전\n✨ 자외선 차단 및 저진동 설계로 맛 보존\n💰 신혼부부 선물용 포장 서비스 제공\n▶ 구경하기', '', 340000.00, 1700),
(12117, 1, '🧖 의류 관리기 5벌 대용량 모델', '', '✨ 온 가족 외출복 한 번에 스타일링 하세요\n💎 미세먼지 코스로 외부 오염 완벽 케어\n📌 렌탈 전환 시 매달 포인트 적립 혜택\n▶ 상세 보기', '', 1630000.00, 8150),
(12118, 1, '🧼 12인용 빌트인 식기세척기', '', '✨ 고온 직수 살균 세척으로 기름때 완벽 제거\n🔥 세척 후 자동 문 열림으로 건조 성능 강화\n💰 전문 기사 방문 사전 상담 서비스 무료\n▶ 구매하기', '', 1020000.00, 5100),
(12119, 1, '💨 접이식 여행용 드라이기 1500W', '', '✨ 강력한 풍량과 휴대성을 동시에 잡았습니다\n🔥 듀얼 전압 지원으로 해외 어디서든 사용\n🎁 전용 파우치 및 돼지코 변환기 증정\n▶ 더 보기', '', 410000.00, 2050),
(12120, 1, '🎮 울트라 와이드 커브드 모니터 34인치', '', '🚀 21:9 비율로 느끼는 압도적인 게임 몰입감\n✨ 눈 보호 모드 탑재로 장시간 사용도 안심\n💰 한정 수량 게이밍 헤드셋 증정 이벤트\n▶ 바로가기', '', 1700000.00, 8500),
(12121, 1, '🧊 미니 냉동고 60L 세컨드 가전', '', '🚗 얼음과 아이스크림 전용으로 활용하기 최고\n✨ 슬림한 가로 폭으로 틈새 수납 가능\n💰 주방 소가전 기획전 추가 5% 할인\n▶ 쇼핑하기', '', 1090000.00, 5450),
(12122, 1, '🔊 하이엔드 사운드 오디오 시스템', '', '✨ 원음 그대로의 감동을 전하는 하이파이 음질\n💎 거실의 품격을 높여주는 고급 원목 마감\n📌 청음샵 예약 방문 시 사은품 증정\n▶ 구경하기', '', 480000.00, 2400),
(12123, 1, '🥩 멀티 전기 포트 1.5L 자취생용', '', '🔥 라면부터 찌개, 찜까지 냄비 없이 해결\n✨ 화이트 톤의 깔끔한 디자인과 간편 세척\n💰 자취 가전 세트 구매 시 추가 10% 할인\n▶ 제품 보기', '', 1770000.00, 8850),
(12124, 1, '🧥 전동 코털 제거기 프리미엄형', '', '✨ 통증 없이 깔끔하게 관리하는 그루밍 필수템\n💎 완전 방수로 샤워 중에도 사용 가능\n📌 선물용 케이스 포함 패키지 판매 중\n▶ 구매하기', '', 1160000.00, 5800),
(12125, 1, '💡 모션 센서 야간 조등 3개 세트', '', '✨ 밤눈 어두운 복도나 현관에 자동 점등\n📱 건전지 걱정 없는 USB 충전식 설계\n💰 1+1 묶음 구성으로 집안 곳곳 설치\n▶ 상세 보기', '', 550000.00, 2750),
(12126, 1, '🍚 당질 저감 건강 밥솥 10인용', '', '✨ 탄수화물 최대 40% 절감, 밥맛은 꿀맛\n💎 대가족 건강 관리를 위한 탁월한 선택\n📌 다이어트 레시피 가이드북 증정\n▶ 쇼핑하기', '', 1840000.00, 9200),
(12127, 1, '🌬️ 초강력 스탠드 서큘레이터 팬', '', '🍃 에어컨 바람을 집안 구석구석 전달하세요\n✨ 상하좌우 무소음 회전과 24단 풍량\n💰 주말 주문 시 배송비 전액 지원 혜택\n▶ 더 보기', '', 1230000.00, 6150),
(12128, 1, '🧳 무선 핸디 스팀 다리미 프로', '', '✨ 선이 없어 자유로운 강력 고온 스팀\n💎 어떤 옷감도 손상 없이 매끄럽게 다림질\n📌 바쁜 아침 1분 컷 스타일 완성템\n▶ 구매하기', '', 620000.00, 3100),
(12129, 1, '🧖 전기 발 마사지기 공기압형', '', '✨ 하루의 피로를 풀어주는 손 지압 방식\n💎 온열 기능 포함으로 붓기 제거에 효과적\n💰 부모님 효도 선물 베스트 셀러 상품\n▶ 상세 보기', '', 1910000.00, 9550),
(12130, 1, '📸 브이로그용 콤팩트 카메라 G7X', '', '✨ 한 손에 쏙 들어가는 고화질 영상 촬영\n💎 틸트 LCD로 셀카 촬영도 편리하게\n🎁 메모리카드 128G 무료 업그레이드\n▶ 구경하기', '', 1300000.00, 6500),
(12131, 1, '💧 스마트 제습기 20L 거실용', '', '✨ 하루 20리터 강력 제습으로 쾌적한 여름\n💎 신발 건조 키트 포함으로 활용도 만점\n💰 얼리버드 특가 한정 수량 100대 진행\n▶ 쇼핑하기', '', 690000.00, 3450),
(12132, 1, '🥗 탄산수 제조기 소다 스트림', '', '🍎 시럽만 넣으면 홈메이드 에이드 완성\n✨ 전기 없이 버튼만 누르면 탄산 주입\n📌 전용 시럽 3종 스타터 키트 포함\n▶ 제품 보기', '', 1980000.00, 9900),
(12133, 1, '⌨️ 펜타그래프 슬림 무선 키보드', '', '✨ 도서관에서도 사용 가능한 저소음 타이핑\n💎 일체형 메탈 프레임으로 견고한 내구성\n💰 사무용 기기 기획전 무료 배송 중\n▶ 구매하기', '', 1370000.00, 6850),
(12134, 1, '🧴 듀얼 UV 칫솔 살균기 거치대', '', '✨ 칫솔과 면도기를 동시에 살균 관리\n💎 태양광 충전 기능으로 선 없는 욕실 완성\n📌 깔끔한 욕실 정리를 위한 필수 아이템\n▶ 더 보기', '', 760000.00, 3800),
(12135, 1, '⌚ 혈압 측정 기능 스마트워치 6세대', '', '🏃 부모님 건강 지킴이, 실시간 혈압 체크\n✨ 낙상 감지 및 긴급 호출 기능 탑재\n💰 구매 시 보호자 앱 연동 무상 지원\n▶ 바로가기', '', 150000.00, 750),
(12136, 1, '🍲 멀티 쿠커 라면 포트 1인용', '', '🔥 사무실이나 캠핑장에서 즐기는 따끈한 국물\n✨ 뚜껑이 거치대로 변신하는 스마트 설계\n📌 1인 가구 삶의 질 수직 상승 가전\n▶ 쇼핑하기', '', 1440000.00, 7200),
(12137, 1, '🌬️ 타워 선풍기 저소음 슬림형', '', '🍃 좁은 방 공간 차지는 줄이고 풍량은 강력\n✨ 필터가 내장되어 먼지 없는 깨끗한 바람\n💰 런칭 기념 기간 한정 20% 세일\n▶ 제품 보기', '', 830000.00, 4150),
(12138, 1, '🧊 가정용 제빙기 급속 6분 생산', '', '❄️ 기다림 없이 쏟아지는 깨끗한 얼음\n✨ 얼음 크기 2단계 조절 및 자동 세척 기능\n💰 지금 사면 전용 얼음 주머니 증정\n▶ 구매하기', '', 220000.00, 1100),
(12139, 1, '🚿 스마트 절수형 온열 비데', '', '✨ 사용자를 인식하는 자동 시트 온열 기능\n💎 절전 모드로 전기세 걱정 없이 사용\n🎁 필터 1년치(4개) 추가 증정 이벤트\n▶ 상세 보기', '', 1510000.00, 7550),
(12140, 1, ' waffle 붕어빵 메이커 4구형', '', '✨ 아이들 간식 걱정 끝! 미니 붕어빵 완성\n💎 교체 가능한 플레이트로 활용도 200%\n📌 주말 가족 브런치 필수 장비\n▶ 쇼핑하기', '', 900000.00, 4500),
(12141, 1, '🔌 스마트 조명 스위치 교체형', '', '✨ 누워서 폰으로 불 끄기! 스마트 홈 시작\n💎 외출 시 전등 소등 여부 확인 가능\n💰 2구/3구 세트 구매 시 설치 가이드 제공\n▶ 구매하기', '', 290000.00, 1450),
(12142, 1, '🏋️ 종아리 마사지기 무선형 세트', '', '✨ 주무르고 두드리는 시원한 공기압 케어\n💎 벨크로 타입으로 사이즈 조절 자유로움\n🎁 런칭 기념 양쪽 세트 구매 할인 중\n▶ 제품 보기', '', 1580000.00, 7900),
(12143, 1, '🥩 무연 전기 그릴 연기 잡는 불판', '', '🥩 실내 고기 파티의 혁명, 연기 흡입 시스템\n✨ 원터치 온도 조절로 초보자도 셰프처럼\n💰 전용 가방 및 구이용 도구 세트 포함\n▶ 구경하기', '', 970000.00, 4850),
(12144, 1, '🧥 침구 살균 청소기 하이파워', '', '👟 1분 8,000번 진동으로 깊은 먼지까지 쏙\n✨ 눈에 보이지 않는 진드기 99% 살균\n📌 아이 있는 집 필수 출산 선물 추천\n▶ 구매하기', '', 360000.00, 1800),
(12145, 1, '💨 도어 부착형 미니 공기청정기', '', '🍃 현관문 뒤에 딱! 외부 먼지 유입 차단\n✨ 슬림하고 강력한 필터로 실내 공기 관리\n💰 설치비 없는 셀프 부착 방식 특가\n▶ 쇼핑하기', '', 1650000.00, 8250),
(12146, 1, '🥛 전동 우유 거품기 크리미 프로', '', '✨ 쫀쫀하고 부드러운 우유 거품을 집에서\n💎 핫초코부터 말차 라떼까지 완벽 조제\n📌 홈카페 바리스타로 변신해 보세요\n▶ 제품 보기', '', 1040000.00, 5200),
(12147, 1, '🧖 갈바닉 LED 마스크 300구', '', '✨ 3가지 파장으로 탄력과 미백을 한 번에\n💎 하루 10분 투자로 달라지는 피부 결\n💰 렌탈 시 전용 수분 앰플 정기 배송\n▶ 상세 보기', '', 430000.00, 2150),
(12148, 1, '🧴 초음파 콘택트렌즈 세척기', '', '✨ 눈의 피로를 줄여주는 단백질 제거 기술\n💎 렌즈 통보다 작은 콤팩트한 휴대성\n📌 렌즈 사용자라면 꼭 써봐야 할 신세계\n▶ 구매하기', '', 1720000.00, 8600),
(12149, 1, '🌡️ 안구 건조증 완화 온열 마사지기', '', '✨ 따뜻한 스팀과 진동으로 눈의 피로 회복\n💎 충전형으로 잠들기 전 어디서나 사용 가능\n💰 오늘 하루만 30% 선착순 타임 세일\n▶ 쇼핑하기', '', 1110000.00, 5550),
(12150, 1, '🔋 캠핑용 대용량 파워뱅크 500W', '', '📱 노지 캠핑에서도 가전제품 마음껏 사용\n✨ 다양한 포트 지원으로 노트북 충전도 거뜬\n💰 전용 태양광 패널 추가 구매 할인\n▶ 제품 보기', '', 500000.00, 2500);
