INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12151, 1, '📺 시네마틱 빔 프로젝터 8K', '', '✨ 거실 벽면을 꽉 채우는 압도적 스케일과 화질\n💎 낮에도 선명한 안시 루멘 성능의 극치\n📌 영화 매니아를 위한 궁극의 홈시네마 가전\n▶ 바로가기', '', 1790000.00, 8950),
(12152, 1, '🧊 4도어 패밀리 허브 냉장고', '', '🎨 주방의 중심! 냉장고 문에 달린 스마트 스크린\n✨ 식재료 관리부터 메모, 음악 재생까지 한 번에\n💰 구형 냉장고 반납 시 최대 30만원 보상\n▶ 쇼핑하기', '', 1180000.00, 5900),
(12153, 1, '🧺 AI 워시타워 콤팩트 에디션', '', '🤖 알아서 무게와 오염도를 감지하는 스마트 세탁\n✨ 좁은 세탁실을 위한 최적의 일체형 디자인\n🚀 전국 무료 배송 및 전문 기사 설치 보장\n▶ 제품 보기', '', 570000.00, 2850),
(12154, 1, '💻 고성능 워크스테이션 노트북 17인치', '', '🚀 3D 렌더링부터 영상 편집까지 끊김 없는 성능\n✨ 고해상도 디스플레이로 정확한 색감 구현\n🎁 정품 가죽 파우치 및 블루투스 마우스 증정\n▶ 상세 보기', '', 1860000.00, 9300),
(12155, 1, '💨 초강력 공기청정기 대형 평수용', '', '🍃 넓은 거실과 주방을 한 번에 케어하는 파워\n✨ 미세먼지 수치를 LED로 한눈에 확인하세요\n🎯 렌탈 가입 시 주기적 필터 교체 서비스 포함\n▶ 렌탈 문의', '', 1250000.00, 6250),
(12156, 1, '🧹 펫 전용 무선 청소기 세트', '', '✨ 반려동물 털 엉킴 방지 브러쉬 탑재\n🤖 강력한 흡입력과 5단계 미세먼지 차단 시스템\n💰 런칭 기념 추가 배터리 무상 증정 이벤트\n▶ 구매하기', '', 640000.00, 3200),
(12157, 1, '🥘 에어프라이어 전자레인지 올인원', '', '🔥 굽고 튀기고 데우는 기능을 기기 하나로 끝\n✨ 주방 공간 효율을 높여주는 스마트 주방 가전\n📌 구매 고객 전용 오븐 전용 용기 세트 증정\n▶ 더 보기', '', 1930000.00, 9650),
(12158, 1, '🧊 서랍형 와인 냉장고 미니멀', '', '🥬 소중한 와인을 위한 최적의 온도 유지 시스템\n✨ 어디에나 잘 어울리는 세련된 글라스 도어\n💰 에너지 소모 효율 1등급, 전기세 걱정 끝\n▶ 쇼핑하기', '', 1320000.00, 6600),
(12159, 1, '☕ 전자동 커피 머신 홈 바리스타', '', '✨ 원두 가공부터 스팀까지 버튼 하나로 완성\n💎 집에서도 카페 퀄리티의 라떼를 즐겨보세요\n📌 구매 시 프리미엄 블렌딩 원두 2kg 증정\n▶ 구경하기', '', 710000.00, 3550),
(12160, 1, '🔋 태양광 무선 충전 패드', '', '🔥 햇빛만 있으면 충전 OK! 친환경 가전의 시작\n✨ 아웃도어 활동이나 비상시 매우 유용합니다\n💰 1+1 묶음 세트 할인 기획전 진행 중\n▶ 상세 보기', '', 100000.00, 500),
(12161, 1, '🥤 얼음 직수 정수기 듀얼 살균', '', '❄️ 얼음과 물 모두 직수로 더 깨끗하고 신선하게\n✨ UV-C LED 살균으로 코크까지 안심 케어\n🎁 신규 가입 시 첫 달 렌탈료 면제 혜택\n▶ 상담 신청', '', 1390000.00, 6950),
(12162, 1, '🥘 3구 인덕션 와이드형 설치형', '', '🔥 가스 불보다 빠른 화력으로 요리 시간 단축\n✨ 상판 청소가 쉬운 고급 세라믹 유리 채택\n💰 기존 가스레인지 철거 및 무료 설치 지원\n▶ 확인하기', '', 780000.00, 3900),
(12163, 1, '🌬️ 초미세풍 BLDC 무선 선풍기', '', '🍃 선 없이 자유롭게 이동하며 즐기는 시원함\n✨ 24단계 세밀한 풍량 조절로 아기에게도 안심\n📌 스마트폰 앱으로 원격 제어 기능 포함\n▶ 구매하기', '', 170000.00, 850),
(12164, 1, '📺 스마트 TV 전용 사운드 플레이어', '', '✨ TV 아래 쏙! 풍부한 서라운드 사운드 선사\n💎 블루투스 스피커로도 활용 가능한 멀티 가전\n💰 세트 구매 시 전용 광케이블 무상 제공\n▶ 제품 보기', '', 1460000.00, 7300),
(12165, 1, '🍞 와플 & 크로플 메이커 교체형', '', '✨ 주말 아침 우리 집을 홈카페로 만들어주는 비결\n🥐 플레이트 분리 세척으로 깔끔한 유지 관리\n📌 아이들 간식용으로 인기 폭발 중인 제품\n▶ 쇼핑하기', '', 850000.00, 4250),
(12166, 1, '🍷 프리미엄 빌트인 냉장고 세트', '', '🍇 주방 인테리어의 완성, 가구와 완벽한 조화\n✨ 맞춤형 색상 선택으로 나만의 주방을 디자인\n💰 신축 아파트 입주 가전 특별 할인 패키지\n▶ 구경하기', '', 240000.00, 1200),
(12167, 1, '🧖 신개념 살균 의류 건조기 5kg', '', '✨ 1인 가구에 딱! 수건과 속옷 살균 건조 전문\n💎 설치가 간편한 컴팩트 사이즈와 저소음 설계\n📌 런칭 기념 필터 6개월분 추가 증정\n▶ 상세 보기', '', 1530000.00, 7650),
(12168, 1, '🧼 6인용 카운터탑 식기세척기 프로', '', '✨ 설거지 해방! 고온 살균과 강력 세정의 힘\n🔥 자동 문 열림으로 남은 습기까지 완벽 제거\n💰 기간 한정 전용 식세기 세제 1년치 증정\n▶ 구매하기', '', 920000.00, 4600),
(12169, 1, '💨 전문가용 드라이기 2200W 파워', '', '✨ 바쁜 아침 모발 손상 없이 초고속 건조\n🔥 3단계 온도와 2단계 풍속 조절로 맞춤 케어\n🎁 전용 스타일링 노즐 및 거치대 포함\n▶ 더 보기', '', 310000.00, 1550),
(12170, 1, '🎮 4K 게이밍 모니터 144Hz 초고사양', '', '🚀 찰나의 순간도 놓치지 않는 빠른 응답 속도\n✨ HDR 기술로 더 생생하고 선명한 게임 화면\n💰 한정 수량 게이밍 키보드 사은품 이벤트\n▶ 바로가기', '', 1600000.00, 8000),
(12171, 1, '🧊 미니 화장품 냉장고 무소음형', '', '🚗 화장품의 영양 성분을 지켜주는 최적의 온도\n✨ 침대 옆에 두어도 조용한 펠티어 냉각 방식\n💰 20대 여성 선물 선호도 1위 뷰티 가전\n▶ 쇼핑하기', '', 990000.00, 4950),
(12172, 1, '🔊 레트로 감성 블루투스 오디오', '', '✨ 거실 분위기를 살리는 클래식한 목재 디자인\n💎 아날로그 라디오 기능과 스마트폰 연동의 만남\n📌 오늘만 반값 특가! 선착순 100명 한정\n▶ 구경하기', '', 380000.00, 1900),
(12173, 1, '🥩 전기 멀티 찜질기 무선 벨트형', '', '🔥 장소 제약 없이 배와 허리를 따뜻하게 케어\n✨ 보드라운 소재와 3단계 온도 조절 시스템\n💰 부모님 효도 선물용 고급 포장 발송 중\n▶ 제품 보기', '', 1670000.00, 8350),
(12174, 1, '🧥 스마트 전동 칫솔 블랙 에디션', '', '✨ 분당 4만 번의 진동으로 플라그 완벽 제거\n💎 스마트폰 앱 연동으로 양치 습관 분석 케어\n📌 구매 시 교체용 칫솔모 4개 세트 증정\n▶ 구매하기', '', 1060000.00, 5300),
(12175, 1, '💡 스마트 LED 무드등 앱 제어', '', '✨ 1,600만 가지 색상으로 방 안 분위기를 변신\n📱 수면 모드와 알람 연동으로 편안한 기상\n💰 신제품 출시 기념 2+1 기획전 참여하기\n▶ 상세 보기', '', 450000.00, 2250),
(12176, 1, '🍚 미니 밥솥 3인용 자취생 필수템', '', '✨ 작지만 강력한 밥맛! 쾌속 취사 기능 탑재\n💎 깔끔한 화이트 디자인으로 데스크테리어 완성\n📌 원룸 거주자 및 캠핑용으로 강력 추천\n▶ 쇼핑하기', '', 1740000.00, 8700),
(12177, 1, '🌬️ 초강력 스탠드 에어 서큘레이터', '', '🍃 에어컨 냉기를 집안 구석구석 빠르게 순환\n✨ 12m 이상 뻗어가는 강력한 바람의 파워\n💰 2대 구매 시 거실+침실 동시 할인 혜택\n▶ 더 보기', '', 1130000.00, 5650),
(12178, 1, '🧳 핸디형 스팀 다리미 접이식', '', '✨ 예열 단 20초! 출장이나 여행 시 필수 아이템\n💎 옷걸이에 걸린 채로 슥슥 문지르면 다림질 끝\n📌 전용 파우치와 브러쉬 노즐 기본 포함\n▶ 구매하기', '', 520000.00, 2600),
(12179, 1, '🧖 전기 발 마사지기 공기압 풀세트', '', '✨ 발바닥부터 종아리까지 시원하게 주물러주는 행복\n💎 온열 기능으로 족욕 효과까지 한 번에 누리세요\n💰 부모님 명절 선물 베스트셀러 1위 선정\n▶ 상세 보기', '', 1810000.00, 9050),
(12180, 1, '📸 미러리스 카메라 입문자 풀패키지', '', '✨ 누구나 작가가 되는 고화질 렌즈 교환식 카메라\n💎 셀카 촬영에 최적화된 회전형 LCD 탑재\n🎁 메모리카드 64GB 및 가방 무상 증정\n▶ 구경하기', '', 1200000.00, 6000),
(12181, 1, '💧 강력 제습기 16L 장마철 대비', '', '✨ 꿉꿉한 집안 공기를 뽀송하게 바꿔주는 강력 제습\n💎 신발 건조 전용 키트로 젖은 운동화도 걱정 끝\n💰 얼리버드 파격 세일! 지금 준비하세요\n▶ 쇼핑하기', '', 590000.00, 2950),
(12182, 1, '🥗 요구르트 제조기 대용량 가족형', '', '🍎 첨가물 제로! 우리 아이를 위한 건강 요거트\n✨ 우유 팩 통째로 넣어 만드는 간편한 방식\n📌 다이어트 식단용 그릭 요거트 제조 가능\n▶ 제품 보기', '', 1880000.00, 9400),
(12183, 1, '⌨️ 블루투스 멀티 페어링 키보드', '', '✨ PC, 태블릿, 폰까지 기기 3대를 동시에 연결\n💎 타이핑 소음이 적어 사무실에서 쓰기 딱 좋아요\n💰 사무용 가전 기획전 무료 배송 혜택\n▶ 구매하기', '', 1270000.00, 6350),
(12184, 1, '🧴 초음파 안경 세척기 스마트 홈', '', '✨ 보이지 않는 틈새 오염을 3분 만에 완벽 제거\n💎 안경뿐 아니라 액세서리, 면도날도 세척 가능\n📌 깔끔한 당신을 위한 스마트한 관리 습관\n▶ 더 보기', '', 660000.00, 3300),
(12185, 1, '⌚ 스마트워치 헬스 매니저 프로', '', '🏃 심박수, 산소포화도부터 수면 분석까지 꼼꼼하게\n✨ 강력한 방수 기능으로 수영 중에도 기록 가능\n💰 런칭 기념 정품 스트랩 1종 추가 증정\n▶ 바로가기', '', 1950000.00, 9750),
(12186, 1, '🍲 멀티 전기 포트 라면 냄비 1.2L', '', '🔥 캠핑장과 사무실에서 즐기는 갓 끓인 라면\n✨ 화상 방지 2중 단열 구조로 더 안전합니다\n📌 1인 가구 선물용으로 가장 인기 있는 모델\n▶ 쇼핑하기', '', 1340000.00, 6700),
(12187, 1, '🌬️ 이동식 냉풍기 아이스 쿨러', '', '🍃 물과 아이스팩으로 시원한 자연풍 선사\n✨ 에어컨보다 전기료가 훨씬 저렴해 경제적\n💰 전용 특수 아이스팩 4개 세트 증정 중\n▶ 제품 보기', '', 730000.00, 3650),
(12188, 1, '🧊 가정용 급속 제빙기 6분 완성', '', '❄️ 기다림 없이 쏟아지는 깨끗한 얼음의 행복\n✨ 홈카페와 홈술을 즐기는 분들을 위한 필수가전\n💰 지금 구매 시 얼음 보관 가방 무상 제공\n▶ 구매하기', '', 120000.00, 600),
(12189, 1, '🚿 자동 거품 디스펜서 센서형', '', '✨ 손만 대면 몽글몽글 거품이 나오는 위생 관리\n💎 건전지 교체 없는 USB 충전식 설계\n🎁 1+1 기획 구성으로 욕실과 주방을 스마트하게\n▶ 상세 보기', '', 1410000.00, 7050),
(12190, 1, '🍞 미니 화로구이 전기 그릴', '', '✨ 식탁 위에서 바로 구워 먹는 꼬치구이와 고기\n💎 연기 발생을 최소화한 실내 전용 설계\n📌 혼술족의 낭만을 완성해주는 아이템\n▶ 쇼핑하기', '', 800000.00, 4000),
(12191, 1, '🔌 스마트 멀티탭 원격 제어형', '', '✨ 밖에서도 집안 가전 전원을 끄고 켤 수 있습니다\n💎 전기료 아끼는 대기전력 자동 차단 기능\n💰 3구/5구 모델 중 선택 및 추가 할인 중\n▶ 구매하기', '', 190000.00, 950),
(12192, 1, '🏋️ 진동 마사지건 30단계 조절', '', '✨ 운동 전후 근육 피로를 시원하게 풀어주는 파워\n💎 6가지 헤드로 부위별 맞춤형 케어 가능\n🎁 전용 하드 케이스 및 교체용 헤드 풀세트\n▶ 제품 보기', '', 1480000.00, 7400),
(12193, 1, '🥩 가정용 고기 숙성고 50L', '', '🥩 집에서도 셰프처럼! 프리미엄 숙성육을 직접\n✨ 정밀한 온도와 습도 제어로 실패 없는 숙성\n💰 고기 매니아들을 위한 특별 한정판 출시\n▶ 구경하기', '', 870000.00, 4350),
(12194, 1, '🧥 신발 살균 건조기 장마철 필수', '', '👟 눅눅해진 운동화 냄새와 세균을 한 번에 해결\n✨ 매일 신고 나가는 신발을 뽀송하게 관리하세요\n📌 출근 전 상쾌함을 선사하는 스마트 가전\n▶ 구매하기', '', 260000.00, 1300),
(12195, 1, '💨 탁상용 미니 공기청정기', '', '🍃 내 책상 위 나만의 맑은 공기를 느껴보세요\n✨ USB 전원 방식으로 어디서나 사용 가능\n💰 1+1 묶음 구매 시 반값 할인 혜택 진행\n▶ 쇼핑하기', '', 1550000.00, 7750),
(12196, 1, '🥛 전동 두유 제조기 500ml', '', '✨ 콩만 넣으면 따끈한 수제 두유가 20분 만에\n💎 건강한 아침 식사 대용으로 최고입니다\n📌 구매 고객께 국산 백태 1kg 증정 이벤트\n▶ 제품 보기', '', 940000.00, 4700),
(12197, 1, '🧖 초음파 피부 관리기 갈바닉', '', '✨ 화장품 흡수율을 높여주는 스마트 뷰티 가전\n💎 온열과 냉각 기능으로 모공 관리까지 한 번에\n💰 전문가용 에스테틱 기기 특가 행사 중\n▶ 상세 보기', '', 330000.00, 1650),
(12198, 1, '🧴 칫솔 살균 거치대 패밀리형', '', '✨ 가족 모두의 칫솔을 위생적으로 관리하는 습관\n💎 UV-C LED 살균으로 세균 번식 99% 억제\n📌 타공 없이 간편하게 설치 가능한 디자인\n▶ 구매하기', '', 1620000.00, 8100),
(12199, 1, '🌡️ 비접촉식 디지털 체온계', '', '✨ 1초 만에 정확한 측정, 가정 상비 필수 가전\n💎 아기부터 성인까지 위생적으로 사용 가능\n💰 건강 가전 기획전 특별 할인가 판매 중\n▶ 쇼핑하기', '', 1010000.00, 5050),
(12200, 1, '🔋 급속 무선 충전 거치대 3in1', '', '📱 스마트폰, 워치, 이어폰을 깔끔하게 한 번에\n✨ 선 꼬임 없는 쾌적한 데스크 공간을 만드세요\n💰 구매 시 전용 고출력 어댑터 무료 증정\n▶ 제품 보기', '', 400000.00, 2000);
