INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12201, 1, '📺 올레드 TV 83인치 시네마 에디션', '', '✨ 백라이트 없는 자발광 픽셀이 만드는 완벽한 블랙\n💎 거실을 압도하는 대화면으로 즐기는 OTT 콘텐츠\n📌 프리미엄 설치 서비스 및 무상 A/S 기간 연장\n▶ 바로가기', '', 1690000.00, 8450),
(12202, 1, '🧊 비스포크 무풍 에어컨 갤러리', '', '🍃 직바람 없이 시원한 무풍 냉방으로 쾌적한 여름\n✨ 가구 같은 디자인으로 거실 인테리어 완성\n💰 에너지 효율 1등급 환급금 신청 가이드 제공\n▶ 쇼핑하기', '', 1080000.00, 5400),
(12203, 1, '🧺 건조기용 양모 볼 6개 세트', '', '✨ 건조 시간을 단축하고 옷감 엉킴을 방지하세요\n💎 화학 성분 없는 천연 소재로 정전기까지 예방\n🚀 가전 소모품 카테고리 판매 1위 아이템\n▶ 제품 보기', '', 470000.00, 2350),
(12204, 1, '💻 듀얼 스크린 고사양 노트북', '', '🚀 두 개의 화면으로 작업 효율을 2배로 높이세요\n✨ 그래픽 작업 및 주식 트레이딩 최적화 모델\n🎁 전용 스타일러스 펜 및 슬리브 케이스 증정\n▶ 상세 보기', '', 1760000.00, 8800),
(12205, 1, '💨 대용량 가습기 10L 복합식', '', '🍃 거실 전체를 촉촉하게! 따뜻한 가습과 시원한 가습\n✨ 통세척이 간편한 구조로 위생적인 관리 가능\n🎯 지금 구매 시 전용 세척 솔 및 필터 증정\n▶ 제품 보기', '', 1150000.00, 5750),
(12206, 1, '🧹 물걸레 전용 로봇청소기 스핀형', '', '✨ 손으로 닦는 듯한 강력한 회전 압력 청소\n🤖 스마트 맵핑으로 카펫은 피해서 꼼꼼하게\n💰 렌탈 전환 시 월 이용료 할인 혜택 제공\n▶ 구매하기', '', 540000.00, 2700),
(12207, 1, '🥘 저당 전기 밥솥 6인용', '', '🔥 탄수화물을 줄여주는 건강한 밥 짓기 기술\n✨ 혈당 관리가 필요한 부모님께 최고의 선물\n📌 구매 고객 전용 잡곡 세트 2kg 증정\n▶ 더 보기', '', 1830000.00, 9150),
(12208, 1, '🧊 빌트인 슬림 냉동고 100L', '', '🥬 부족한 냉동 공간, 틈새 가전으로 해결하세요\n✨ 성에 없는 간접 냉각 방식과 깔끔한 디자인\n💰 신선 가전 기획전 특별 할인가 판매 중\n▶ 쇼핑하기', '', 1220000.00, 6100),
(12209, 1, '☕ 에스프레소 수동 머신 홈바리스타', '', '✨ 직접 내리는 재미와 깊은 풍미의 에스프레소\n💎 감성적인 메탈 디자인으로 주방의 품격 상승\n📌 원두 그라인더 세트 구매 시 추가 할인\n▶ 구경하기', '', 610000.00, 3050),
