INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12251, 1, '📺 100인치 초거대 QLED TV', '', '✨ 거실 한계를 넘는 압도적 스케일과 생생한 색감\n💎 AI 화질 엔진으로 저해상도 영상도 4K급으로\n📌 홈시어터 마니아를 위한 끝판왕 가전\n▶ 바로가기', '', 1590000.00, 7950),
(12252, 1, '🧊 비스포크 슈케이스 & 슈케어', '', '🎨 소중한 스니커즈를 전시하고 관리하는 신개념 가전\n✨ 살균, 건조, 탈취까지 한 번에 끝내는 혁신\n💰 한정판 신발 수집가 필수 소장템 런칭 혜택\n▶ 쇼핑하기', '', 980000.00, 4900),
(12253, 1, '🧺 건조기용 드라이 시트 120매', '', '✨ 빨래 건조 후 풍부한 향기와 부드러운 촉감\n💎 정전기 방지 기능으로 옷감 손상을 최소화\n🚀 가전 소모품 카테고리 재구매율 1위\n▶ 제품 보기', '', 370000.00, 1850),
(12254, 1, '💻 폴더블 디스플레이 노트북', '', '🚀 펼치면 모니터, 접으면 노트북! 혁신적인 폼팩터\n✨ 업무 환경을 자유롭게 바꾸는 차세대 PC\n🎁 전용 키보드 및 가죽 파우치 풀세트 증정\n▶ 상세 보기', '', 1660000.00, 8300),
(12255, 1, '💨 자연기화식 가습기 저소음형', '', '🍃 물 입자가 가벼워 세균 걱정 없는 깨끗한 가습\n✨ 필터 세척이 간편해 위생적으로 사용 가능\n🎯 아이 있는 집 거실용으로 강력 추천\n▶ 제품 보기', '', 1050000.00, 5250),
(12256, 1, '🧹 로봇청소기 전용 세정제 세트', '', '✨ 바닥의 끈적임과 세균을 한 번에 해결하는 전용 액\n🤖 모든 로봇청소기 기종에 호환 가능한 안전 성분\n💰 3개 세트 구매 시 대용량 리필 추가 증정\n▶ 구매하기', '', 440000.00, 2200),
(12257, 1, '🥘 스마트 압력 멀티쿠커 8in1', '', '🔥 찜, 탕, 볶음부터 요거트까지 기계 하나로\n✨ 터치 한 번으로 완성되는 100가지 자동 레시피\n📌 맞벌이 부부 아침 시간 단축 필수 가전\n▶ 더 보기', '', 1730000.00, 8650),
(12258, 1, '🧊 틈새 냉장고 1도어 120L', '', '🥬 다용도실이나 안방 세컨드 냉장고로 최적\n✨ 슬림한 가로 폭으로 좁은 공간 활용도 극대화\n💰 에너지 소모 효율 우수 가전 환급 대상\n▶ 쇼핑하기', '', 1120000.00, 5600),
(12259, 1, '☕ 캡슐 커피 머신 하이엔드 모델', '', '✨ 19바 고압 추출로 내리는 진한 크레마의 향연\n💎 예열 시간 단축으로 바쁜 아침에도 여유롭게\n📌 스타터 팩 캡슐 30종 무료 증정 이벤트\n▶ 구경하기', '', 510000.00, 2550),
(12260, 1, '🔋 맥세이프 호환 무선 충전 보조배터리', '', '🔥 붙이기만 하면 충전 시작! 선 없는 자유로움\n✨ 거치대 기능까지 포함되어 영상 시청도 편리함\n💰 아이폰 유저 추천 아이템 기획전 진행 중\n▶ 상세 보기', '', 1800000.00, 9000),
(12261, 1, '🥤 정수기 직수관 무상 교체 서비스', '', '❄️ 오래된 정수기, 속까지 새것처럼 관리하세요\n✨ 1년마다 새 직수관으로 교체해 드리는 안심 케어\n🎁 렌탈 고객 대상 연 1회 방문 점검 무료\n▶ 신청하기', '', 1190000.00, 5950),
(12262, 1, '🥘 3구 전기그릴 자이글 에디션', '', '🔥 냄새와 연기를 잡는 상부 적외선 가열 방식\n✨ 기름 튐 방지 구조로 거실에서 즐기는 삼겹살\n💰 전용 보관 가방 및 집게 세트 포함\n▶ 확인하기', '', 580000.00, 2900),
(12263, 1, '🌬️ 캠핑용 무선 서큘레이터 텐트형', '', '🍃 강력한 풍량과 조명 기능을 동시에 갖춘 아이템\n✨ 대용량 배터리로 1박 2일 캠핑도 거뜬함\n📌 등산 및 낚시족에게도 사랑받는 필수 가전\n▶ 구매하기', '', 1870000.00, 9350),
(12264, 1, '📺 프리미엄 TV 벽걸이 브라켓(회전형)', '', '✨ 어느 각도에서도 편하게 시청하는 좌우 회전형\n💎 셋톱박스 숨기기 기능으로 거실벽을 깔끔하게\n💰 전문 기사 방문 설치 포함 패키지 특가\n▶ 제품 보기', '', 1260000.00, 6300),
(12265, 1, '🍞 스팀 토스터기 미니 오븐형', '', '✨ 죽은 빵도 살려내는 5cc 스팀의 마법\n🥐 겉바속촉 베이커리 퀄리티를 집에서 재현\n📌 감성 주방 인테리어의 완성, 화이트 에디션\n▶ 쇼핑하기', '', 650000.00, 3250),
(12266, 1, '🍷 프리미엄 빌트인 냉장고(양문형)', '', '🍇 주방 가구장 속에 쏙! 완벽한 키친테리어 완성\n✨ 맞춤형 컬러 패널로 나만의 스타일 연출\n💰 신규 입주 가전 상담 시 최대 20% 할인\n▶ 구경하기', '', 1940000.00, 9700),
(12267, 1, '🧖 의류 관리기 향기 카트리지 20매', '', '✨ 의류 관리기 사용 시 은은한 아로마 향기 선사\n💎 옷에 밴 불쾌한 냄새를 기분 좋게 바꿔줍니다\n📌 로맨틱 로즈/클린 코튼 두 가지 향 선택 가능\n▶ 상세 보기', '', 1330000.00, 6650),
(12268, 1, '🧼 12인용 대용량 식기세척기(독립형)', '', '✨ 명절 설거지도 한 번에! 압도적 수납 공간\n🔥 100도 고온 살균 세척으로 기름기 완벽 제거\n💰 렌탈 및 장기 할부 구매 프로그램 운영 중\n▶ 구매하기', '', 720000.00, 3600),
(12269, 1, '💨 음이온 발생 헤어 드라이기 프로', '', '✨ 머릿결 손상을 줄여주는 정밀 온도 제어 시스템\n🔥 차원이 다른 풍속으로 건조 시간 50% 단축\n🎁 전용 노즐 3종 및 거치대 무상 증정\n▶ 더 보기', '', 110000.00, 550),
(12270, 1, '🎮 게이밍 커브드 모니터 49인치', '', '🚀 32:9 슈퍼 울트라 와이드 비율의 압도적 몰입감\n✨ 두 개의 모니터를 하나로 쓰는 효율성\n💰 한정 수량 게이밍 마우스패드 증정 이벤트\n▶ 바로가기', '', 1400000.00, 7000),
(12271, 1, '🧊 미니 냉온장고 10L(화장품/음료)', '', '🚗 여름엔 시원하게, 겨울엔 따뜻하게 전환 가능\n✨ 차량용 시가잭 연결로 여행 중에도 편리하게\n💰 캠핑 및 차박 마니아 추천 필수 소형 가전\n▶ 쇼핑하기', '', 790000.00, 3950),
(12272, 1, '🔊 하이파이 북쉘프 스피커 세트', '', '✨ 서재와 거실을 음악으로 채우는 고품격 사운드\n💎 원목 마감으로 어떤 가구와도 조화로운 디자인\n📌 오디오 마니아들이 인정한 가성비 끝판왕\n▶ 구경하기', '', 180000.00, 900),
(12273, 1, '🥩 무선 어깨 찜질기 온열 마사지형', '', '🔥 뻐근한 어깨와 목을 따뜻하게 감싸주는 휴식\n✨ 인체공학적 설계로 착용 후에도 자유로운 활동\n💰 명절 부모님 선물 만족도 1위 상품\n▶ 제품 보기', '', 1470000.00, 7350),
(12274, 1, '🧥 전동 코털 제거기 완전방수형', '', '✨ 아프지 않고 깔끔하게! 그루밍 족의 필수품\n💎 물세척이 가능해 더욱 위생적인 관리가 가능\n📌 선물용 전용 케이스 및 여분 칼날 증정\n▶ 구매하기', '', 860000.00, 4300),
(12275, 1, '💡 스마트 LED 스트립 조명 5m', '', '✨ 침대 밑, TV 뒤에 붙여 만드는 나만의 조명 맛집\n📱 음악 리듬에 맞춰 색상이 변하는 파티 모드\n💰 2개 구매 시 연결 커넥터 무료 증정\n▶ 상세 보기', '', 250000.00, 1250),
(12276, 1, '🍚 3분 취사 쾌속 미니 밥솥', '', '✨ 바쁜 아침, 1인분 밥을 15분 만에 뚝딱\n💎 캠핑용으로도 제격인 초소형 사이즈와 무게\n📌 자취생 삶의 질을 높여주는 필수 소가전\n▶ 쇼핑하기', '', 1540000.00, 7700),
(12277, 1, '🌬️ 초강력 스탠드형 에어 서큘레이터', '', '🍃 에어컨 바람을 20m 밖까지 보내주는 강력한 힘\n✨ 상하좌우 입체 회전으로 실내 온도 균일 유지\n💰 2대 묶음 구매 시 추가 10% 적립 혜택\n▶ 더 보기', '', 930000.00, 4650),
(12278, 1, '🧳 휴대용 스팀 다리미 2in1 모드', '', '✨ 스탠드 스팀과 건식 다림질을 기기 하나로\n💎 접이식 핸들로 캐리어 공간 차지를 최소화\n📌 출장 잦은 직장인의 가방 속 머스트 아이템\n▶ 구매하기', '', 320000.00, 1600),
(12279, 1, '🧖 프리미엄 목 마사지기 저주파형', '', '✨ EMS 저주파와 온열로 깊은 근육까지 케어\n💎 무선 헤드셋 타입으로 휴식 중 사용 편리\n💰 한정 기간 전용 젤 패치 5팩 추가 증정\n▶ 상세 보기', '', 1610000.00, 8050),
(12280, 1, '📸 액션캠 브이로그 풀패키지', '', '✨ 4K 고해상도 영상과 강력한 손떨림 보정 기능\n💎 유튜버 시작을 위한 삼각대, 마이크 세트 구성\n🎁 128GB 고성능 메모리카드 선착순 증정\n▶ 구경하기', '', 1000000.00, 5000),
(12281, 1, '💧 원룸용 미니 제습기 펠티어형', '', '✨ 드레스룸과 화실 습기를 쏙 잡아주는 컴팩트 사이즈\n💎 저소음 설계로 수면 방해 없는 쾌적한 환경\n💰 여름 시즌 오프 파격 할인 가격 공개\n▶ 쇼핑하기', '', 390000.00, 1950),
(12282, 1, '🥗 수제 요구르트 & 치즈 제조기', '', '🍎 우리 아이 간식, 이제 집에서 직접 만드세요\n✨ 버튼 하나로 완성되는 건강한 홈메이드 유산균\n📌 전용 보관 용기 4세트 기본 포함 구성\n▶ 제품 보기', '', 1680000.00, 8400),
(12283, 1, '⌨️ 기계식 키보드 블루투스 텐키리스', '', '✨ 경쾌한 타건감과 공간 효율을 동시에 잡은 모델\n💎 기기 3대 동시 연결 멀티 페어링 기능 탑재\n💰 사무용 기기 리뉴얼 특가전 참여하기\n▶ 구매하기', '', 1070000.00, 5350),
(12284, 1, '🧴 초음파 주얼리 세척기 프리미엄', '', '✨ 금, 은 액세서리부터 안경까지 새것처럼 광택\n💎 강력한 미세 진동으로 보이지 않는 오염 제거\n📌 소중한 예물을 위한 필수 관리 가전\n▶ 더 보기', '', 460000.00, 2300),
(12285, 1, '⌚ 스포츠 스마트워치 철인3종용', '', '🏃 마라톤, 수영, 사이클까지 정밀한 기록 추적\n✨ 태양광 충전 기능으로 최대 30일 배터리 지속\n💰 러닝 동호회 단체 구매 시 특별 혜택 제공\n▶ 바로가기', '', 1750000.00, 8750),
(12286, 1, '🍲 멀티 전기 쿠커 샤브샤브용', '', '🔥 식탁 위에서 바로 즐기는 따끈한 국물 요리\n✨ 반반 냄비 구조로 두 가지 맛을 동시에 즐기기\n📌 집들이 및 가족 모임용으로 추천하는 아이템\n▶ 쇼핑하기', '', 1140000.00, 5700),
(12287, 1, '🌬️ 이동식 냉풍기 리모컨형', '', '🍃 물 보충으로 느끼는 자연의 시원한 바람\n✨ 에어컨 설치가 곤란한 작은 방에 딱 좋습니다\n💰 지금 사면 전용 아이스팩 4개 세트 증정\n▶ 제품 보기', '', 530000.00, 2650),
(12288, 1, '🧊 가정용 자동 제빙기 12kg 대용량', '', '❄️ 홈카페와 홈술을 위한 멈추지 않는 얼음 공급\n✨ 자동 세척 기능으로 위생까지 꼼꼼하게 챙겼습니다\n💰 한정 수량 얼음 주머니 및 전용 삽 증정\n▶ 구매하기', '', 1820000.00, 9100),
(12289, 1, '🚿 자동 거품 비누 디스펜서 2개 세트', '', '✨ 손만 대면 나오는 풍성한 거품, 위생의 시작\n💎 욕실과 주방에 하나씩! 1+1 기획 패키지\n🎁 선물용으로도 좋은 깔끔한 박스 포장 발송\n▶ 상세 보기', '', 1210000.00, 6050),
(12290, 1, '🍞 붕어빵 & 와플 메이커 가정용', '', '✨ 겨울철 국민 간식 붕어빵을 집에서 무제한으로\n💎 다양한 플레이트 교체로 홈브런치까지 OK\n📌 주말 아이들 간식 제조기로 강력 추천\n▶ 쇼핑하기', '', 600000.00, 3000),
(12291, 1, '🔌 스마트 가전 플러그 에너지 모니터링', '', '✨ 폰으로 전력 사용량 확인하고 전원도 끄고 켜기\n💎 과부하 차단 기능으로 화재 예방까지 안심\n💰 3개 세트 구매 시 추가 할인 혜택 제공\n▶ 구매하기', '', 1890000.00, 9450),
(12292, 1, '🏋️ 무선 핸드형 진동 마사지기', '', '✨ 어깨, 허리, 종아리 어디든 시원하게 주무르기\n💎 강력한 모터 파워와 가벼운 무게의 환상 조합\n🎁 부모님 효도 선물 베스트 셀러 상품\n▶ 제품 보기', '', 1280000.00, 6400),
(12293, 1, '🥩 가스식 휴대용 버너 전용 그릴 팬', '', '🥩 캠핑 고기 맛을 살려주는 주물 그리들 팬\n✨ 기름 배출 구조로 담백하게 즐기는 야외 식사\n💰 버너와 세트 구매 시 보관 가방 무상 증정\n▶ 구경하기', '', 670000.00, 3350),
(12294, 1, '🧥 신발 살균 건조기 장마철 에디션', '', '👟 젖은 운동화 냄새와 세균을 한 번에 해결하세요\n✨ 매일 아침 뽀송한 신발을 신는 즐거움\n📌 운동화 매니아들의 필수 위생 가전 아이템\n▶ 구매하기', '', 1960000.00, 9800),
(12295, 1, '💨 탁상용 공기청정기 미세먼지 차단', '', '🍃 내 책상 위 반경 2m를 맑은 공기로 채우기\n✨ 소음이 적어 사무실이나 독서실에서 사용 가능\n💰 런칭 기념 헤파 필터 2개 추가 증정 이벤트\n▶ 쇼핑하기', '', 1350000.00, 6750),
(12296, 1, '🥛 전동 두유 제조기 스마트 센서형', '', '✨ 콩만 넣으면 따끈한 두유가 20분 만에 완성\n💎 조리 중 온도 자동 조절로 영양소 파괴 최소화\n📌 건강한 아침 식사를 준비하는 주부 필수가전\n▶ 제품 보기', '', 740000.00, 3700),
(12297, 1, '🧖 갈바닉 LED 마스크 얼굴 탄력 케어', '', '✨ 하루 15분 투자로 달라지는 피부 톤과 탄력\n💎 안심 설계로 집에서도 안전하게 홈케어 하세요\n💰 뷰티 가전 기획전 특별 할인가 진행 중\n▶ 상세 보기', '', 130000.00, 650),
(12298, 1, '🧴 초음파 콘택트렌즈 세척기 자동형', '', '✨ 렌즈의 단백질 오염을 99% 제거하는 미세진동\n💎 손 대지 않고 세척해 눈 건강을 지켜줍니다\n📌 콤팩트한 사이즈로 파우치에 쏙 들어감\n▶ 구매하기', '', 1420000.00, 7100),
(12299, 1, '🌡️ 온열 진동 눈 마사지기 충전식', '', '✨ 컴퓨터 업무로 지친 눈에 따뜻한 휴식을 선사\n💎 블루투스 음악 연결 기능으로 깊은 힐링\n💰 직장인 선물용 주문 1위 아이템 선정\n▶ 쇼핑하기', '', 810000.00, 4050),
(12300, 1, '🔋 캠핑용 대용량 파워뱅크 2000Wh', '', '📱 노지 캠핑의 필수품! 커피 머신과 전기장판 사용\n✨ 다양한 기기를 동시에 충전하는 멀티 포트 탑재\n💰 태양광 패널 세트 구매 시 파격 할인 혜택\n▶ 제품 보기', '', 200000.00, 1000);
