INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12301, 1, '📺 8K 초고화질 레이저 프로젝터', '', '✨ 영화관의 감동을 집에서! 3,000 안시 루멘의 밝기\n💎 최대 120인치 대화면에도 깨지지 않는 선명함\n📌 홈시어터 매니아를 위한 프리미엄 영상 가전\n▶ 바로가기', '', 1490000.00, 7450),
(12302, 1, '🧊 비스포크 와인 냉장고 빌트인', '', '🎨 주방의 품격을 높이는 맞춤형 컬러 패널\n✨ 와인 종류별 최적 온도를 유지하는 듀얼 존 시스템\n💰 신혼부부 혼수 가전 특별 할인 패키지 제공\n▶ 쇼핑하기', '', 880000.00, 4400),
(12303, 1, '🧺 미니 드럼 세탁기 3.5kg 벽걸이형', '', '🤖 좁은 공간도 OK! 아기 옷이나 속옷 전용으로 딱\n✨ 고온 살균 세탁으로 유해균 99.9% 제거\n🚀 수도권 지역 주문 시 내일 바로 설치 가능\n▶ 제품 보기', '', 270000.00, 1350),
(12304, 1, '💻 크리에이터용 터치 스크린 노트북', '', '🚀 펜 지원 디스플레이로 드로잉과 편집을 한 번에\n✨ 최신 프로세서 탑재로 무거운 작업도 거뜬히\n🎁 전용 정품 스타일러스 펜 및 파우치 증정\n▶ 상세 보기', '', 1560000.00, 7800),
(12305, 1, '💨 스마트 가습 공기청정기 2in1', '', '🍃 맑은 공기와 적정 습도를 기계 하나로 케어\n✨ 자동 감지 센서로 실내 환경 최적화\n🎯 렌탈 가입 시 주기적인 케어 서비스 포함\n▶ 렌탈 문의', '', 950000.00, 4750),
(12306, 1, '🧹 로봇청소기 자동 먼지 비움 스테이션', '', '✨ 청소 후 먼지 통 비우기까지 알아서 척척\n🤖 라이다 센서로 집안 구조를 정밀하게 맵핑\n💰 기간 한정 더스트백 1년치 추가 증정\n▶ 구매하기', '', 340000.00, 1700),
(12307, 1, '🥘 저당 멀티 쿠커 건강 식단용', '', '🔥 탄수화물을 줄인 맛있는 밥과 찜 요리\n✨ 다이어터와 당뇨 환자를 위한 필수 주방 가전\n📌 전용 레시피 북 포함 구성으로 요리 고민 끝\n▶ 더 보기', '', 1630000.00, 8150),
(12308, 1, '🧊 슬림형 김치냉장고 1도어 150L', '', '🥬 공간은 적게 차지하고 수납은 넉넉하게\n✨ 사계절 내내 아삭한 김치 맛을 지켜주는 정온 기술\n💰 에너지 효율 1등급으로 전기료 부담 제로\n▶ 쇼핑하기', '', 1020000.00, 5100),
(12309, 1, '☕ 전자동 에스프레소 머신 실버 에디션', '', '✨ 원두 분쇄부터 추출까지 원터치로 즐기는 카페\n💎 고압 추출로 깊고 진한 크레마를 경험하세요\n📌 구매 시 프리미엄 로스팅 원두 1kg 증정\n▶ 구경하기', '', 410000.00, 2050),
(12310, 1, '🔋 맥세이프 무선 충전 거치대 3in1', '', '🔥 아이폰, 애플워치, 에어팟을 한 번에 충전\n✨ 깔끔한 데스크테리어를 위한 필수 아이템\n💰 2개 이상 구매 시 추가 10% 할인 혜택\n▶ 상세 보기', '', 1700000.00, 8500),
(12311, 1, '🥤 셀프 교체형 직수 정수기 미니', '', '❄️ 관리사 방문 없이 내가 직접 필터 교체\n✨ 좁은 주방에 쏙 들어가는 11cm 슬림 디자인\n🎁 신규 가입 시 신세계 상품권 모바일 발송\n▶ 상담 신청', '', 1090000.00, 5450),
(12312, 1, '🥘 와이드 전기 그릴 70cm 대형', '', '🔥 명절 전 부치기나 가족 고기 파티에 최적\n✨ 눌어붙지 않는 강력한 티타늄 코팅 상판\n💰 보관 가방 및 세척 전용 도구 포함 세트\n▶ 확인하기', '', 480000.00, 2400),
(12313, 1, '🌬️ 무선 탁상용 선풍기 오토 회전', '', '🍃 책상 위에서도 상하좌우 시원한 바람을\n✨ 저소음 설계로 사무실이나 독서실용으로 추천\n📌 대용량 배터리로 캠핑장에서 쓰기 좋습니다\n▶ 구매하기', '', 1770000.00, 8850),
(12314, 1, '📺 차량용 스마트 모니터 15인치', '', '✨ 넷플릭스, 유튜브를 차 안에서 대화면으로\n💎 장거리 여행 시 아이들의 지루함을 달래줄 가전\n💰 전용 거치대 및 시가잭 케이블 패키지\n▶ 제품 보기', '', 1160000.00, 5800),
(12315, 1, '🍞 스팀 미니 오븐 토스터기 화이트', '', '✨ 겉바속촉! 죽은 빵도 살리는 스팀 테크놀로지\n🥐 베이글부터 피자까지 다양하게 조리 가능\n📌 감성 주방을 위한 심플한 북유럽풍 디자인\n▶ 쇼핑하기', '', 550000.00, 2750),
(12316, 1, '🍷 프리미엄 빌트인 냉장고 세트', '', '🍇 가구와 하나되는 완벽한 키친핏 인테리어\n✨ 냉동, 냉장, 김치냉장고를 내 맘대로 조합\n💰 입주 가전 상담 예약 시 사은품 증정\n▶ 구경하기', '', 1840000.00, 9200),
(12317, 1, '🧖 의류 건조기 전용 양모 볼 6입', '', '✨ 건조 시간을 단축하고 옷감을 부드럽게\n💎 화학 섬유 유연제 대신 사용하는 천연 솔루션\n📌 반영구적으로 사용 가능한 가성비 아이템\n▶ 상세 보기', '', 1230000.00, 6150),
(12318, 1, '🧼 6인용 카운터탑 식기세척기 블랙', '', '✨ 설치 걱정 없이 싱크대 위에 쏙!\n🔥 고온 직수 살균 세척으로 기름기 완벽 제거\n💰 전용 식세기 세제 스타터 키트 증정\n▶ 구매하기', '', 620000.00, 3100),
(12319, 1, '💨 고출력 BLDC 헤어 드라이기 프로', '', '✨ 전문가의 손길! 초고속 건조와 모발 보호\n🔥 음이온 기능으로 부스스한 머릿결 정돈\n🎁 전용 거치대 및 스타일링 노즐 3종 증정\n▶ 더 보기', '', 1910000.00, 9550),
(12320, 1, '🎮 울트라 와이드 커브드 게이밍 모니터', '', '🚀 21:9 비율로 더 넓게 보는 전장의 시야\n✨ 165Hz 고주사율로 끊김 없는 플레이\n💰 한정 수량 게이밍 장패드 무상 증정 중\n▶ 바로가기', '', 1300000.00, 6500),
(12321, 1, '🧊 미니 화장품 냉장고 저소음형', '', '🚗 화장품 성분을 지키는 최적의 온도 12도\n✨ 콤팩트한 사이즈로 화장대 위에 딱!\n💰 생일 선물이나 집들이 선물로 인기 만점\n▶ 쇼핑하기', '', 690000.00, 3450),
(12322, 1, '🔊 빈티지 감성 턴테이블 스피커', '', '✨ LP의 아날로그 음색과 블루투스의 편리함\n💎 인테리어 소품으로도 손색없는 클래식 디자인\n📌 입문자를 위한 LP 1장 랜덤 증정 이벤트\n▶ 구경하기', '', 1980000.00, 9900),
(12323, 1, '🥩 멀티 전기 찜질기 어깨/허리용', '', '🔥 뻐근한 몸을 따뜻하게 녹여주는 온열 케어\n✨ 극세사 소재로 포근하고 부드러운 착용감\n💰 효도 선물용 고급 하드 케이스 포장 발송\n▶ 제품 보기', '', 1370000.00, 6850),
(12324, 1, '🧥 음파 전동 칫솔 블랙 에디션', '', '✨ 분당 4만 번의 진동으로 플라그 완벽 제거\n💎 스마트 압력 센서로 잇몸 보호 기능 탑재\n📌 구매 시 교체용 칫솔모 4개 추가 증정\n▶ 구매하기', '', 760000.00, 3800),
(12325, 1, '💡 스마트 LED 스트립 조명 앱 제어', '', '✨ 침대 밑이나 TV 뒤 분위기 있는 무드 연출\n📱 스마트폰으로 1,600만 가지 색상 자유 조절\n💰 2개 세트 구매 시 전용 커넥터 증정\n▶ 상세 보기', '', 150000.00, 750),
(12326, 1, '🍚 1인용 미니 밥솥 캠핑 에디션', '', '✨ 혼밥족이나 캠핑족을 위한 콤팩트 밥솥\n💎 갓 지은 밥맛을 야외에서도 그대로 느끼세요\n📌 화이트/민트/핑크 취향 저격 컬러 출시\n▶ 쇼핑하기', '', 1440000.00, 7200),
(12327, 1, '🌬️ 초강력 스탠드형 에어 서큘레이터', '', '🍃 에어컨 냉기를 집안 곳곳으로 빠르게 순환\n✨ 상하좌우 입체 회전으로 실내 온도 균일 유지\n💰 2대 묶음 할인! 거실과 안방에 하나씩\n▶ 더 보기', '', 830000.00, 4150),
(12328, 1, '🧳 휴대용 핸디 스팀 다리미 폴딩형', '', '✨ 캐리어에 쏙! 출장이나 여행 필수 아이템\n💎 예열 20초로 바쁜 아침 빠른 주름 제거\n📌 전용 보관 파우치 및 브러쉬 헤드 포함\n▶ 구매하기', '', 220000.00, 1100),
(12329, 1, '🧖 전기 발 마사지기 공기압 풀세트', '', '✨ 하루의 피로를 풀어주는 전문가급 지압\n💎 온열 기능 포함으로 족욕 효과까지 동시에\n💰 부모님 추석 선물 베스트셀러 1위 상품\n▶ 상세 보기', '', 1510000.00, 7550),
(12330, 1, '📸 4K 액션캠 브이로그 패키지', '', '✨ 떨림 없는 생생한 여행 영상을 기록하세요\n💎 방수 케이스 포함으로 수중 촬영도 거뜬\n🎁 64GB 고성능 메모리카드 무료 증정\n▶ 구경하기', '', 900000.00, 4500),
(12331, 1, '💧 강력 제습기 16L 장마 대비용', '', '✨ 눅눅한 집안을 뽀송하게! 대용량 물통 탑재\n💎 신발 건조 키트 포함으로 장마철 필수 가전\n💰 얼리버드 특가 한정 수량 100대 진행\n▶ 쇼핑하기', '', 290000.00, 1450),
(12332, 1, '🥗 수제 요구르트 제조기 대용량', '', '🍎 인공 감미료 없는 건강한 수제 요거트\n✨ 우유 팩 통째로 넣어 만드는 간편한 방식\n📌 다이어트 식단용 그릭 요거트 제조 가능\n▶ 제품 보기', '', 1580000.00, 7900),
(12333, 1, '⌨️ 블루투스 접이식 무선 키보드', '', '✨ 스마트폰과 태블릿을 노트북처럼 사용\n💎 가방에 쏙 들어가는 초경량 폴딩 디자인\n💰 비즈니스맨 필수 추천 가성비 아이템\n▶ 구매하기', '', 970000.00, 4850),
(12334, 1, '🧴 듀얼 UV 칫솔 살균기 거치대', '', '✨ 칫솔 5개와 면도기까지 동시에 강력 살균\n💎 타공 없이 깔끔하게 부착하는 욕실 가전\n📌 아이들 양치 습관 잡아주는 스마트 아이템\n▶ 더 보기', '', 360000.00, 1800),
(12335, 1, '⌚ 스마트워치 7세대 헬스 추적기', '', '🏃 혈압, 심박수, 수면 패턴까지 정밀 분석\n✨ 장시간 배터리로 일주일 내내 충전 없이\n💰 정품 스트랩 1+1 추가 증정 이벤트\n▶ 바로가기', '', 1650000.00, 8250),
(12336, 1, '🍲 멀티 전기 냄비 라면 포트 1.5L', '', '🔥 자취생 삶의 질 수직 상승! 만능 쿠커\n✨ 냄비 없이 끓이고 바로 먹는 편리함\n📌 사무실 점심용으로도 인기 만점\n▶ 쇼핑하기', '', 1040000.00, 5200),
(12337, 1, '🌬️ 타워형 선풍기 무소음 슬림', '', '🍃 좁은 방 공간 차지는 줄이고 풍량은 강력하게\n✨ 리모컨 제어로 누워서 편안하게 조절하세요\n💰 런칭 기념 특가 및 배송비 무료 혜택\n▶ 제품 보기', '', 430000.00, 2150),
(12338, 1, '🧊 가정용 제빙기 6분 급속 제빙', '', '❄️ 기다림 없이 쏟아지는 깨끗한 얼음\n✨ 홈카페와 홈술을 즐기는 분들의 필수품\n💰 구매 시 전용 얼음 보관 가방 증정\n▶ 구매하기', '', 1720000.00, 8600),
(12339, 1, '🚿 자동 거품 비누 디스펜서 센서형', '', '✨ 손만 대면 몽글몽글 거품이! 위생적인 욕실\n💎 USB 충전식으로 건전지 교체 번거로움 끝\n🎁 주방과 욕실 세트 구매 시 추가 할인\n▶ 상세 보기', '', 1110000.00, 5550),
(12340, 1, '🍞 샌드위치 & 와플 메이커 교체형', '', '✨ 바쁜 아침 3분 만에 근사한 브런치 완성\n💎 플레이트 분리 세척으로 위생적인 관리\n📌 신혼부부 집들이 선물 만족도 상위 모델\n▶ 쇼핑하기', '', 500000.00, 2500),
(12341, 1, '🔌 스마트 멀티탭 앱 제어 4구', '', '✨ 외출해서도 폰으로 전원을 끄고 켜세요\n💎 대기전력 차단으로 전기 요금 아끼는 비결\n💰 스마트 홈 구축의 시작, 최저가 기획전\n▶ 구매하기', '', 1790000.00, 8950),
(12342, 1, '🏋️ 무선 진동 마사지건 30단계', '', '✨ 운동 전후 근육 피로를 시원하게 풀어주는 파워\n💎 6가지 헤드로 부위별 맞춤 케어 가능\n🎁 전용 하드 케이스 및 교체 헤드 풀세트\n▶ 제품 보기', '', 1180000.00, 5900),
(12343, 1, '🥩 가스식 휴대용 버너(구이바다)', '', '🥩 캠핑 고수들의 추천! 구이와 전골을 하나로\n✨ 전용 가방 포함으로 휴대와 보관이 편리함\n💰 캠핑 시즌 맞이 소품 증정 프로모션\n▶ 구경하기', '', 570000.00, 2850),
(12344, 1, '🧥 침구 살균 청소기 UV 지능형', '', '👟 우리 가족 잠자리, 진드기와 먼지 완벽 차단\n✨ 고온 열풍 건조로 뽀송뽀송한 침구 유지\n📌 반려동물 키우는 집엔 필수 가전입니다\n▶ 구매하기', '', 1860000.00, 9300),
(12345, 1, '💨 탁상용 미니 공기청정기 USB', '', '🍃 내 책상 위 나만의 맑은 공기를 느껴보세요\n✨ 3단계 필터로 미세먼지와 냄새를 싹\n💰 1+1 묶음 구매 시 추가 15% 할인 진행\n▶ 쇼핑하기', '', 1250000.00, 6250),
(12346, 1, '🥛 전동 두유 제조기 스마트 홈', '', '✨ 콩만 넣으면 따끈한 두유가 20분 만에 완성\n💎 이유식이나 건강 죽 요리도 버튼 하나로\n📌 아침 식사 대용으로 강력 추천하는 가전\n▶ 제품 보기', '', 640000.00, 3200),
(12347, 1, '🧖 갈바닉 피부 관리기 홈에스테틱', '', '✨ 화장품 흡수를 돕고 탄력을 높여주는 케어\n💎 집에서 관리하는 프리미엄 뷰티 솔루션\n💰 런칭 기념 전용 앰플 3종 무료 증정\n▶ 상세 보기', '', 1930000.00, 9650),
(12348, 1, '🧴 초음파 안경 세척기 스마트', '', '✨ 안경 틈새 먼지와 기름기를 단숨에 제거\n💎 액세서리나 시계 줄도 새것처럼 세척하세요\n📌 깔끔한 이미지 관리를 위한 필수 기기\n▶ 구매하기', '', 1320000.00, 6600),
(12349, 1, '🌡️ 온열 진동 눈 마사지기 무선', '', '✨ 피로한 눈에 휴식을! 온열과 지압 기능 탑재\n💎 수면 전 15분, 꿀잠을 부르는 힐링 가전\n💰 직장인 선물용 주문 폭주 아이템 선정\n▶ 쇼핑하기', '', 710000.00, 3550),
(12350, 1, '🔋 캠핑용 대용량 파워뱅크 500Wh', '', '📱 노지 캠핑의 필수품! 다양한 기기 동시 충전\n✨ 노트북부터 미니 냉장고까지 거뜬히 사용\n💰 전용 가방 및 태양광 패널 추가 할인\n▶ 제품 보기', '', 100000.00, 500);
