INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12351, 1, '📺 98인치 초대형 AI Neo QLED', '', '✨ 거실을 영화관으로 만드는 압도적 크기와 화질\n💎 AI 프로세서가 장면별로 최적의 명암비 조절\n📌 대형 가전 전용 프리미엄 설치 서비스 포함\n▶ 바로가기', '', 1390000.00, 6950),
(12352, 1, '🧊 비스포크 무풍 에어컨 갤러리', '', '🎨 가구 같은 디자인으로 인테리어와 완벽 조화\n✨ 직바람 없이 시원한 무풍 냉방으로 쾌적하게\n💰 에너지 소비효율 1등급 환급 대상 모델\n▶ 쇼핑하기', '', 780000.00, 3900),
(12353, 1, '🧺 건조기용 아로마 드라이 시트 80매', '', '✨ 빨래 끝! 건조기 사용 후 남는 기분 좋은 향기\n💎 정전기 방지와 옷감 보호를 한 번에 해결\n🚀 가전 소모품 카테고리 누적 판매 1위\n▶ 제품 보기', '', 170000.00, 850),
(12354, 1, '💻 고성능 워크스테이션급 노트북', '', '🚀 3D 렌더링부터 영상 편집까지 끊김 없이\n✨ 초고주사율 디스플레이로 부드러운 화면 전환\n🎁 전용 백팩 및 게이밍 마우스 증정 이벤트\n▶ 상세 보기', '', 1460000.00, 7300),
(12355, 1, '💨 초음파식 미니 가습기 LED형', '', '🍃 책상 위 건조함을 해결하는 컴팩트 가습기\n✨ 무드등 기능으로 밤에는 아늑한 분위기 연출\n🎯 세척이 간편한 상부 급수형 구조\n▶ 제품 보기', '', 850000.00, 4250),
(12356, 1, '🧹 로봇청소기 전용 극세사 걸레 세트', '', '✨ 찌든 때까지 닦아내는 고밀도 극세사 원사\n🤖 주요 브랜드 로봇청소기 기종 완벽 호환\n💰 10매 묶음 구매 시 배송비 무료 혜택\n▶ 구매하기', '', 240000.00, 1200),
(12357, 1, '🥘 저당 식단용 스마트 당질저감 밥솥', '', '🔥 밥맛은 그대로, 탄수화물만 쏙 뺀 건강 가전\n✨ 다이어트와 건강 관리를 시작하는 분께 추천\n📌 전용 저당 조리용 트레이 기본 포함\n▶ 더 보기', '', 1530000.00, 7650),
(12358, 1, '🧊 다용도실 틈새 냉장고 150L', '', '🥬 좁은 공간을 효율적으로 쓰는 슬림 디자인\n✨ 음료 전용 냉장고나 서브 가전으로 최적\n💰 자취생 및 소형 가구 인기 모델 특가전\n▶ 쇼핑하기', '', 920000.00, 4600),
(12359, 1, '☕ 홈카페용 반자동 커피 머신', '', '✨ 내가 직접 내리는 풍부한 향의 에스프레소\n💎 강력한 스팀 밀크 노즐로 라떼 아트까지 도전\n📌 초보자용 탬퍼 및 피쳐 풀세트 증정\n▶ 구경하기', '', 310000.00, 1550),
(12360, 1, '🔋 고속 무선 충전 패드 15W', '', '🔥 올려만 두면 충전 끝! 강력한 무선 출력\n✨ 과열 방지 센서 탑재로 밤새 안전하게 충전\n💰 아이폰 & 갤럭시 유저 공용 호환 모델\n▶ 상세 보기', '', 1600000.00, 8000),
(12361, 1, '🥤 직수형 얼음 정수기 렌탈 서비스', '', '❄️ 깨끗한 직수로 만든 투명하고 단단한 얼음\n✨ UV 살균 시스템으로 코크까지 안심 관리\n🎁 가입 시 초기 설치비 면제 및 사은품 증정\n▶ 상담 신청', '', 990000.00, 4950),
(12362, 1, '🥘 연기 잡는 안심 전기 그릴', '', '🔥 연기와 냄새를 흡입하는 팬 내장형 구조\n✨ 거실에서 즐기는 쾌적한 삼겹살 파티\n💰 명절 대비 가족 모임용 특가 진행 중\n▶ 확인하기', '', 380000.00, 1900),
(12363, 1, '🌬️ 캠핑용 무선 선풍기 서큘레이터형', '', '🍃 야외에서도 시원하게! 강력한 BLDC 모터\n✨ 대용량 배터리로 무선 사용 시간 극대화\n📌 텐트 천장 거치용 고리 디자인 설계\n▶ 구매하기', '', 1670000.00, 8350),
(12364, 1, '📺 대형 TV 전용 이동식 거치대(스탠드)', '', '✨ 거실에서도 침실에서도 이동하며 시청하기\n💎 견고한 스틸 프레임과 부드러운 우레탄 바퀴\n💰 셀프 설치 시 추가 적립금 혜택 제공\n▶ 제품 보기', '', 1060000.00, 5300),
(12365, 1, '🍞 레트로 디자인 미니 토스터기', '', '✨ 주방 분위기를 바꾸는 감성적인 색감\n🥐 6단계 굽기 조절로 취향에 맞는 토스트 완성\n📌 신혼부부 집들이 선물 베스트 아이템\n▶ 쇼핑하기', '', 450000.00, 2250),
(12366, 1, '🍷 키친핏 양문형 냉장고 오브제형', '', '🍇 가구와 일체감을 주는 돌출 없는 디자인\n✨ 맞춤형 도어 패널로 나만의 주방 완성\n💰 구형 냉장고 반납 시 보상 판매 이벤트\n▶ 구경하기', '', 1740000.00, 8700),
(12367, 1, '🧖 의류 관리기 전용 향기 시트', '', '✨ 외출 후 옷에 밴 냄새를 숲속 향기로 리프레시\n💎 섬유 유연 성분 함유로 옷감 정전기 방지\n📌 대용량 100매 구성으로 넉넉하게 사용\n▶ 상세 보기', '', 1130000.00, 5650),
(12368, 1, '🧼 빌트인 14인용 식기세척기 프로', '', '✨ 많은 설거지도 한 번에! 더 넓어진 수납 공간\n🔥 75도 고온 살균 세척으로 99.9% 제균\n💰 브랜드 기획전 기간 내 설치비 전액 무료\n▶ 구매하기', '', 520000.00, 2600),
(12369, 1, '💨 전문가용 이온 헤어 드라이기', '', '✨ 찰랑거리는 머릿결을 위한 음이온 케어\n🔥 강력한 풍압으로 바쁜 아침 건조 시간 단축\n🎁 집중 노즐 및 디퓨저 노즐 기본 증정\n▶ 더 보기', '', 1810000.00, 9050),
(12370, 1, '🎮 240Hz 게이밍 모니터 27인치', '', '🚀 0.5ms 응답 속도로 즐기는 승부의 세계\n✨ 끊김 없는 화면 전환으로 압도적 몰입감\n💰 PC방 오픈 및 교체 수요 대량 구매 상담\n▶ 바로가기', '', 1200000.00, 6000),
(12371, 1, '🧊 화장품 냉장고 미러 디자인 12L', '', '🚗 문 전체가 거울로 된 세련된 뷰티 가전\n✨ 스킨케어 제품을 최적의 온도로 신선하게\n💰 화장대 위 인테리어 소품으로도 만점\n▶ 쇼핑하기', '', 590000.00, 2950),
(12372, 1, '🔊 블루투스 북쉘프 스피커 액티브형', '', '✨ 입체적인 사운드로 채우는 나만의 음악 공간\n💎 TV, 스마트폰과 간편하게 연결되는 호환성\n📌 오디오 애호가들이 극찬한 입문용 명기\n▶ 구경하기', '', 1880000.00, 9400),
(12373, 1, '🥩 무선 목 어깨 마사지기 온열형', '', '🔥 뭉친 근육을 손으로 주무르는 듯한 시원함\n✨ 인체공학적 C자 커브 설계로 밀착 케어\n💰 어버이날 효도 선물 예약 구매 시 할인\n▶ 제품 보기', '', 1270000.00, 6350),
(12374, 1, '🧥 전동 보풀 제거기 대형 헤드형', '', '✨ 헌 옷도 새 옷처럼! 강력한 6중 회전날\n💎 니트나 코트 상함 없이 보풀만 말끔히 제거\n📌 USB 충전식으로 어디서나 간편하게 사용\n▶ 구매하기', '', 660000.00, 3300),
(12375, 1, '💡 스마트 LED 데스크 램프 4모드', '', '✨ 독서, 집중, 휴식 모드로 시력 보호 케어\n📱 스마트폰 무선 충전 패드 내장형 스마트 스탠드\n💰 신학기 학생용 가전 선물 세트 구성\n▶ 상세 보기', '', 1950000.00, 9750),
(12376, 1, '🍚 자취생 미니 전기밥솥 3인용', '', '✨ 작지만 강하다! 잡곡밥까지 맛있는 취사\n💎 에너지 효율 1등급으로 전기세 걱정 뚝\n📌 1인 가구를 위한 콤팩트한 주방 가전\n▶ 쇼핑하기', '', 1340000.00, 6700),
(12377, 1, '🌬️ 초강력 스탠드형 에어 서큘레이터', '', '🍃 에어컨 냉기를 집안 곳곳으로 빠르게 순환\n✨ 상하좌우 입체 회전으로 실내 온도 균일 유지\n💰 2대 묶음 할인! 거실과 안방에 하나씩\n▶ 더 보기', '', 730000.00, 3650),
(12378, 1, '🧳 여행용 미니 스팀 다리미 2in1', '', '✨ 가방에 쏙 들어가는 사이즈, 성능은 강력하게\n💎 핸디형 스팀과 바닥형 다림질 모두 가능\n📌 출장 잦은 직장인의 수트 관리 필수템\n▶ 구매하기', '', 120000.00, 600),
(12379, 1, '🧖 전기 발 마사지기 공기압 3D', '', '✨ 발바닥부터 발등까지 빈틈없는 압박 마사지\n💎 3단계 강도 조절과 따뜻한 온열 기능\n💰 부모님 명절 선물 선호도 1위 아이템\n▶ 상세 보기', '', 1410000.00, 7050),
(12380, 1, '📸 브이로그용 4K 액션 카메라', '', '✨ 생생한 현장감을 담는 고해상도 영상 촬영\n💎 방수 케이스 없이도 수심 10m 방수 지원\n🎁 셀카봉 및 여분 배터리 2개 패키지 구성\n▶ 구경하기', '', 800000.00, 4000),
(12381, 1, '💧 강력 제습기 18L 자동 습도 조절', '', '✨ 장마철에도 뽀송하게! 대용량 수조 탑재\n💎 의류 건조 모드로 빨래 냄새 걱정 끝\n💰 제습기 미리 구매 프로모션 최대 할인\n▶ 쇼핑하기', '', 190000.00, 950),
(12382, 1, '🥗 그릭 요거트 메이커 유청 분리기', '', '🍎 집에서 만드는 꾸덕한 건강 수제 요거트\n✨ 인공 첨가물 없이 순수하게 즐기는 디저트\n📌 다이어트 식단 관리의 필수 주방 가전\n▶ 제품 보기', '', 1480000.00, 7400),
(12383, 1, '⌨️ 무선 기계식 키보드 텐키리스', '', '✨ 경쾌한 타건감과 공간 활용을 위한 컴팩트형\n💎 멀티 페어링으로 PC, 태블릿 동시 연결\n💰 사무용 데스크테리어 기획전 진행 중\n▶ 구매하기', '', 870000.00, 4350),
(12384, 1, '🧴 초음파 안경 및 주얼리 세척기', '', '✨ 안경 틈새 먼지부터 액세서리 광택까지\n💎 3분이면 끝나는 미세 진동 초강력 세척\n📌 가족 모두가 만족하는 생활 위생 가전\n▶ 더 보기', '', 260000.00, 1300),
(12385, 1, '⌚ 스마트워치 액티브 스포츠용', '', '🏃 달리기, 수영 기록을 손목 위에서 확인\n✨ 산소 포화도와 스트레스 지수까지 정밀 측정\n💰 한정 기간 전용 메탈 스트랩 무료 증정\n▶ 바로가기', '', 1550000.00, 7750),
(12386, 1, '🍲 멀티 전기 쿠커 라면 포트 1.8L', '', '🔥 냄비와 가스레인지가 필요 없는 만능 포트\n✨ 자취생이나 사무실 간편식 조리용 추천\n📌 투명 강화유리 뚜껑으로 요리 과정 확인\n▶ 쇼핑하기', '', 940000.00, 4700),
(12387, 1, '🌬️ 무소음 타워 선풍기 리모컨형', '', '🍃 날개 없는 안전한 구조로 아이 있는 집 추천\n✨ 슬림한 디자인으로 거실 구석에 쏙!\n💰 시즌 오프 파격 할인 가격으로 만나보세요\n▶ 제품 보기', '', 330000.00, 1650),
(12388, 1, '🧊 급속 제빙기 15kg 대용량', '', '❄️ 홈카페와 캠핑장에서 끊임 없는 얼음 공급\n✨ 자동 세척 기능으로 내부까지 깨끗하게 관리\n💰 구매 시 전용 스쿱 및 보관 파우치 증정\n▶ 구매하기', '', 1620000.00, 8100),
(12389, 1, '🚿 자동 비누 디스펜서 센서형 블랙', '', '✨ 손만 대면 나오는 풍성한 미세 거품\n💎 욕실 분위기를 바꾸는 시크한 블랙 디자인\n🎁 1+1 세트 구매 시 전용 세정액 리필 증정\n▶ 상세 보기', '', 1010000.00, 5050),
(12390, 1, '🍞 붕어빵 와플 메이커 교체판 포함', '', '✨ 우리 집이 붕어빵 맛집! 겨울철 인기 가전\n💎 샌드위치 플레이트로 홈브런치도 간편하게\n📌 아이들과 함께 만드는 즐거운 간식 시간\n▶ 쇼핑하기', '', 400000.00, 2000),
(12391, 1, '🔌 스마트 AI 플러그 에너지 관리', '', '✨ 가전제품 대기전력을 폰으로 완벽 차단\n💎 전기 요금 아끼는 가장 쉬운 IoT 솔루션\n💰 이사/입주 고객 5개 세트 특별 패키지\n▶ 구매하기', '', 1690000.00, 8450),
(12392, 1, '🏋️ 진동 마사지건 프로 30단계 조절', '', '✨ 운동 후 뭉친 근육을 풀어주는 강력한 타격감\n💎 저소음 설계와 대용량 배터리로 여유로운 사용\n🎁 전용 하드 케이스 및 6종 헤드 풀세트\n▶ 제품 보기', '', 1080000.00, 5400),
(12393, 1, '🥩 휴대용 가스 버너 슬림 화이트', '', '🥩 감성 캠핑의 완성! 깔끔하고 예쁜 디자인 버너\n✨ 강력한 내연식 화력으로 바람 불어도 안심\n💰 전용 수납 가방 포함 특가 프로모션\n▶ 구경하기', '', 470000.00, 2350),
(12394, 1, '🧥 신발 살균 건조기 장마 대비용', '', '👟 눅눅한 운동화와 신발 속 세균을 단숨에 제거\n✨ 매일 아침 새 신발처럼 뽀송한 기분을 선물\n📌 등산이나 운동을 즐기는 분들의 필수 가전\n▶ 구매하기', '', 1760000.00, 8800),
(12395, 1, '💨 탁상용 공기청정기 필터 2개 포함', '', '🍃 사무실 책상이나 공부방을 위한 개인 청정기\n✨ 초미세먼지를 99.9% 걸러내는 헤파필터\n💰 런칭 기념 선착순 100대 할인 판매\n▶ 쇼핑하기', '', 1150000.00, 5750),
(12396, 1, '🥛 홈메이드 두유 제조기 자동 가열', '', '✨ 불린 콩만 넣으면 따끈한 두유가 완성\n💎 조리부터 세척까지 원터치로 끝내는 편리함\n📌 건강한 아침 식습관을 위한 필수 아이템\n▶ 제품 보기', '', 540000.00, 2700),
(12397, 1, '🧖 갈바닉 LED 마스크 얼굴 탄력용', '', '✨ 하루 10분, 집에서 받는 전문 피부 케어\n💎 안심 설계와 자동 꺼짐 기능으로 안전하게\n💰 뷰티 가전 파격 세일 이벤트 참여하기\n▶ 상세 보기', '', 1830000.00, 9150),
(12398, 1, '🧴 초음파 콘택트렌즈 세척기 미니', '', '✨ 눈의 피로를 줄여주는 렌즈 단백질 완벽 제거\n💎 화장품 케이스 크기로 휴대성이 뛰어남\n📌 장시간 렌즈 착용자를 위한 건강 가전\n▶ 구매하기', '', 1220000.00, 6100),
(12399, 1, '🌡️ 온열 진동 눈 마사지기 힐링 모드', '', '✨ 지친 눈에 따뜻한 온기과 부드러운 공기압 지압\n💎 블루투스 내장으로 음악과 함께 즐기는 휴식\n💰 선물용 박스 포장 및 무료 배송 서비스\n▶ 쇼핑하기', '', 610000.00, 3050),
(12400, 1, '🔋 캠핑용 대용량 파워뱅크 1000Wh', '', '📱 노지 캠핑에서도 노트북과 냉장고 사용 가능\n✨ 다양한 출력 포트로 동시 충전도 문제 없음\n💰 지금 구매 시 전용 보호 가방 추가 증정\n▶ 제품 보기', '', 1900000.00, 9500);
