INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12401, 1, '📺 프리미엄 4K OLED TV 65인치', '', '✨ 무한대 명암비로 구현하는 완벽한 블랙의 깊이\n💎 초슬림 페이퍼 디자인으로 벽과의 일체감 극대화\n📌 영화 감독이 의도한 색감을 그대로 재현\n▶ 바로가기', '', 1290000.00, 6450),
(12402, 1, '🧊 비스포크 인피니트 라인 냉장고', '', '🎨 변치 않는 가치를 담은 타임리스 알루미늄 소재\n✨ 센서로 문을 여는 오토 오픈 도어 시스템 탑재\n💰 프리미엄 가전 구매 고객 대상 VIP 케어 서비스\n▶ 쇼핑하기', '', 680000.00, 3400),
(12403, 1, '🧺 대용량 건조기 20kg 올인원 컨트롤', '', '✨ 세탁기에서 건조기까지 한 번에 제어하는 편리함\n💎 AI 맞춤 건조로 세탁물 무게와 습도 정밀 감지\n🚀 대가족 빨래 고민을 덜어주는 압도적 용량\n▶ 제품 보기', '', 1970000.00, 9850),
