(12441, 1, '🔌 IoT 스마트 멀티탭 4구 전력 측정', '', '✨ 폰으로 실시간 전기 사용량 확인 및 차단\n💎 깜빡하고 안 끈 가전제품, 외출 중에도 제어\n💰 에너지 절약 가계부의 첫걸음 스마트 가전\n▶ 구매하기', '', 1590000.00, 7950),
(12442, 1, '🏋️ 무선 핸드 마사지기 6종 헤드형', '', '✨ 목, 어깨, 종아리 등 부위별 맞춤형 케어\n💎 강력한 모터로 깊은 근육까지 시원하게 마사지\n🎁 명절 효도 선물용 전용 쇼핑백 동봉 발송\n▶ 제품 보기', '', 980000.00, 4900),
(12443, 1, '🥩 휴대용 인덕션 1구 핑크 에디션', '', '🥩 식탁 위 분위기를 살려주는 예쁜 조리 도구\n✨ 화력이 강력해 야외 캠핑에서도 메인으로 사용\n💰 런칭 기념 전용 인덕션 냄비 세트 할인 판매\n▶ 구경하기', '', 370000.00, 1850),
(12444, 1, '🧥 신발 살균기 건조기 고온 건조형', '', '👟 장마철 젖은 신발을 쾌속으로 말려드립니다\n✨ 자외선 살균 기능으로 무좀균 및 악취 제거\n📌 운동화, 구두, 부츠까지 전용 노즐로 케어\n▶ 구매하기', '', 1660000.00, 8300),
(12445, 1, '💨 탁상용 공기청정기 저소음 슬림', '', '🍃 내 책상 주변 공기를 정화하는 퍼스널 청정기\n✨ 3단계 고효율 필터로 비염과 먼지 고민 해결\n💰 신학기 학생용 가전 선물 세트 구성 상품\n▶ 쇼핑하기', '', 1050000.00, 5250),
(12446, 1, '🥛 전자동 두유기 영양 죽 제조기', '', '✨ 마른 콩만 넣어도 부드러운 두유가 완성\n💎 조리부터 고온 살균 세척까지 한 번에 끝\n📌 건강한 아침 식사를 원하는 직장인 필수템\n▶ 제품 보기', '', 440000.00, 2200),
(12447, 1, '🧖 갈바닉 피부 마사지기 LED 테라피', '', '✨ 화장품 성분을 피부 깊숙이 전달하는 탄력 케어\n💎 집에서 즐기는 전문가 수준의 에스테틱 기술\n💰 한정 기간 전용 마스크 팩 10매 추가 증정\n▶ 상세 보기', '', 1730000.00, 8650),
(12448, 1, '🧴 초음파 안경 세척기 스마트 로즈', '', '✨ 미세 진동으로 안경의 보이지 않는 오염 제거\n💎 주얼리와 시계 줄 세척도 가능한 멀티 기능\n📌 깔끔한 이미지 관리를 위한 나만의 뷰티 가전\n▶ 구매하기', '', 1120000.00, 5600),
(12449, 1, '🌡️ 온열 눈 마사지기 릴렉스 사운드', '', '✨ 하루 15분, 지친 눈에 따뜻한 휴식을 선물하세요\n💎 내장된 힐링 음악으로 마음까지 편안하게\n💰 직장인 및 수험생 선물용으로 강력 추천\n▶ 쇼핑하기', '', 510000.00, 2550),
(12450, 1, '🔋 캠핑용 대용량 파워뱅크 1500Wh', '', '📱 노지 캠핑의 필수품! 대용량으로 더 여유롭게\n✨ 전기장판부터 빔프로젝터까지 모두 사용 가능\n💰 지금 구매 시 태양광 패널 추가 할인 혜택\n▶ 제품 보기', '', 1800000.00, 9000);
