INSERT INTO tbl_advertisement (id, advertiser_id, title, headline, description, landing_url, budget, impression_estimate) OVERRIDING SYSTEM VALUE VALUES
(12451, 1, '📺 110인치 마이크로 LED TV', '', '✨ 차세대 디스플레이 기술이 선사하는 자발광의 감동\n💎 베젤이 없는 인피니티 스크린으로 몰입감 극대화\n📌 럭셔리 홈 엔터테인먼트의 정점을 경험하세요\n▶ 바로가기', '', 1190000.00, 5950),
(12452, 1, '🧊 비스포크 와인 냉장고 인피니트', '', '🎨 시간이 흘러도 변치 않는 고급스러운 메탈 디자인\n✨ 와인 종류에 맞춘 최적의 습도와 온도 정밀 제어\n💰 구매 시 전문 소믈리에 와인 클래스 초대권 증정\n▶ 쇼핑하기', '', 580000.00, 2900),
(12453, 1, '🧺 미니 건조기 5kg UV 살균형', '', '✨ 1인 가구 및 수건 전용으로 딱 맞는 콤팩트 사이즈\n💎 고온 살균과 UV 케어로 유해 세균 99.9% 제거\n🚀 설치 걱정 없는 배수관 무설치 간편 방식\n▶ 제품 보기', '', 1870000.00, 9350),
(12454, 1, '💻 초경량 고성능 비즈니스 노트북', '', '🚀 1kg 미만의 무게로 하루 종일 가볍게 휴대\n✨ 최신 프로세서와 고용량 배터리로 끊김 없는 업무\n🎁 전용 가죽 파우치 및 무선 마우스 세트 증정\n▶ 상세 보기', '', 1260000.00, 6300),
(12455, 1, '💨 대용량 가열식 가습기 5L', '', '🍃 물을 끓여서 가습하는 가장 깨끗한 방식\n✨ 세균 걱정 없는 따뜻한 수증기로 실내 온도 유지\n🎯 통세척이 가능한 구조로 관리가 매우 간편합니다\n▶ 제품 보기', '', 650000.00, 3250),
(12456, 1, '🧹 로봇청소기 전용 일회용 물걸레', '', '✨ 세탁 필요 없이 한 장씩 뜯어 쓰는 위생적 관리\n🤖 강력한 엠보싱 원단으로 바닥 찌든 때 완벽 제거\n💰 대용량 100매 구성 패키지 특가 기획전\n▶ 구매하기', '', 1940000.00, 9700),
(12457, 1, '🥘 스마트 멀티 압력솥 6in1', '', '🔥 찜, 국, 볶음, 수비드까지 버튼 하나로 완성\n✨ 바쁜 일상을 돕는 예약 조리 및 자동 보온 기능\n📌 전용 레시피 가이드북 포함으로 요리 초보 탈출\n▶ 더 보기', '', 1330000.00, 6650),
(12458, 1, '🧊 슬림형 서랍 냉장고 120L', '', '🥬 소파 옆이나 침대 옆에 두는 프리미엄 서브 가전\n✨ 화장품, 음료, 간식을 최상의 상태로 보관\n💰 인테리어의 품격을 높이는 세련된 가구 스타일\n▶ 쇼핑하기', '', 720000.00, 3600),
(12459, 1, '☕ 캡슐 커피 머신 에센자 화이트', '', '✨ 버튼 한 번으로 즐기는 나만의 홈카페 타임\n💎 좁은 공간에도 어울리는 가장 슬림한 사이즈\n📌 캡슐 수거 서비스 참여 시 포인트 적립 혜택\n▶ 구경하기', '', 110000.00, 550),
(12460, 1, '🔋 3in1 고속 무선 충전 스테이션', '', '🔥 폰, 워치, 이어폰을 한 자리에서 깔끔하게 충전\n✨ 과전류 방지 스마트 칩 탑재로 기기 수명 보호\n💰 데스크테리어족을 위한 심플한 디자인\n▶ 상세 보기', '', 1400000.00, 7000),
(12461, 1, '🥤 셀프 관리 직수 정수기 스노우', '', '❄️ 관리사 방문 없이 내가 직접 관리하는 필터\n✨ 12cm 초슬림 사이즈로 주방 공간 활용 극대화\n🎁 신규 가입 시 첫 달 렌탈료 무료 프로모션\n▶ 상담 신청', '', 790000.00, 3950),
(12462, 1, '🥘 3단 전기 찜기 대용량 멀티형', '', '🔥 영양소 파괴 없이 즐기는 건강한 다이어트 식단\n✨ 층별로 고기, 야채, 해산물을 한 번에 조리\n💰 간편한 다이얼 방식으로 누구나 쉽게 사용\n▶ 확인하기', '', 180000.00, 900),
(12463, 1, '🌬️ 탁상용 무소음 선풍기 USB형', '', '🍃 독서실이나 사무실에서 눈치 보지 않고 시원하게\n✨ 360도 각도 조절로 나만의 풍향 맞춤 설정\n📌 콤팩트한 사이즈로 가방에 쏙 들어가는 휴대성\n▶ 구매하기', '', 1470000.00, 7350),
(12464, 1, '📺 모니터 전용 LED 조명 바(Bar)', '', '✨ 눈의 피로를 줄여주는 비대칭 광학 설계 조명\n💎 모니터 위에 거치하여 책상 공간 활용 극대화\n💰 야간 작업이 많은 직장인/학생 필수 아이템\n▶ 제품 보기', '', 860000.00, 4300),
(12465, 1, '🍞 레트로 토스터기 민트 에디션', '', '✨ 주방에 생기를 불어넣는 상큼한 민트 컬러\n🥐 해동, 재가열, 취소 등 꼭 필요한 기능 탑재\n📌 결혼 선물 및 이사 선물로 가장 선호되는 가전\n▶ 쇼핑하기', '', 250000.00, 1250),
(12466, 1, '🍷 빌트인 냉장고 도어 패널 교체형', '', '🍇 가구장에 딱 맞춘 키친핏으로 완성하는 주방\n✨ 취향에 따라 선택하는 무광/유광 다양한 소재\n💰 입주 가전 견적 상담 시 추가 할인권 증정\n▶ 구경하기', '', 1540000.00, 7700),
(12467, 1, '🧖 의류 관리기 전용 아로마 필터', '', '✨ 옷장에 숲속 향기를 가득 채우는 아로마틱 케어\n💎 불쾌한 냄새는 잡고 기분 좋은 잔향만 남깁니다\n📌 소중한 옷을 위한 마지막 한끗, 향기 관리\n▶ 상세 보기', '', 930000.00, 4650),
(12468, 1, '🧼 카운터탑 식기세척기 6인용 프로', '', '✨ 싱크대 위에 바로 설치하는 편리한 식기세척기\n🔥 자동 문 열림 건조 기능으로 물때 걱정 끝\n💰 자사몰 단독 구매 시 세제 1년치 무료 배송\n▶ 구매하기', '', 320000.00, 1600),
(12469, 1, '💨 접이식 여행용 드라이기 1200W', '', '✨ 강력한 바람은 그대로, 사이즈는 절반으로\n🔥 전 세계 어디서나 사용 가능한 프리볼트 기능\n🎁 전용 휴대용 파우치 기본 포함 구성\n▶ 더 보기', '', 1610000.00, 8050),
(12470, 1, '🎮 게이밍 노트북 17인치 RTX 40시리즈', '', '🚀 고사양 게임도 풀옵션으로 즐기는 압도적 사양\n✨ 듀얼 쿨링 시스템으로 발열 걱정 없는 플레이\n💰 게이밍 마우스 및 전용 키스킨 증정 이벤트\n▶ 바로가기', '', 1000000.00, 5000),
(12471, 1, '🧊 화장품 냉장고 에코 슬림 10L', '', '🚗 스킨케어 흡수율을 높이는 최적의 온도 유지\n✨ 소음 걱정 없는 펠티어 소자 냉각 방식 적용\n💰 뷰티 인플루언서들이 추천하는 필수 관리 가전\n▶ 쇼핑하기', '', 390000.00, 1950),
(12472, 1, '🔊 레트로 블루투스 스피커 우드 에디션', '', '✨ 따뜻한 원목 감성과 풍부한 베이스 사운드\n💎 인테리어 가구와 조화로운 클래식 디자인\n📌 캠핑이나 피크닉 시 휴대하기 좋은 핸들 장착\n▶ 구경하기', '', 1680000.00, 8400),
(12473, 1, '🥩 저주파 EMS 미니 마사지기', '', '🔥 작지만 강력하다! 원하는 부위에 붙여서 케어\n✨ 스마트폰 연동으로 강도와 모드 자유 조절\n💰 1+1 기획 구성으로 선물하기 좋은 아이템\n▶ 제품 보기', '', 1070000.00, 5350),
(12474, 1, '🧥 전동 운동화 세탁기 가정용', '', '✨ 손빨래 힘드시죠? 운동화 전용 브러쉬로 세척\n💎 찌든 때와 냄새를 한 번에 해결하는 특수 공법\n📌 아이들 신발 세탁이 잦은 집엔 필수 가전\n▶ 구매하기', '', 460000.00, 2300),
(12475, 1, '💡 스마트 전구 색온도 조절형', '', '✨ 주백색에서 전구색까지 상황에 맞는 분위기 연출\n📱 음성 명령으로 불을 끄고 켜는 편리함\n💰 스마트 홈 패키지 구매 시 전용 스위치 증정\n▶ 상세 보기', '', 1750000.00, 8750),
(12476, 1, '🍚 미니멀 전기 밥솥 1인용 화이트', '', '✨ 혼밥도 맛있게! 갓 지은 밥을 즐기는 가장 쉬운 방법\n💎 에너지 소모 효율 1등급의 알뜰한 주방 가전\n📌 모던하고 깔끔한 디자인으로 자취방 필수템\n▶ 쇼핑하기', '', 1140000.00, 5700),
(12477, 1, '🌬️ 초강력 스탠드 서큘레이터 12인치', '', '🍃 공기 순환을 넘어 선풍기 대용으로도 충분한 파워\n✨ 상하좌우 입체 회전으로 실내 온도 균일화\n💰 런칭 기념 특가 판매 및 2년 무상 AS 보장\n▶ 더 보기', '', 530000.00, 2650),
(12478, 1, '🧳 휴대용 보풀 제거기 무선형', '', '✨ 니트와 코트를 새 옷처럼 관리하는 마법\n💎 3단계 칼날 높이 조절로 옷감 손상 방지\n📌 한 손에 쏙 들어오는 인체공학적 그립감\n▶ 구매하기', '', 1820000.00, 9100),
(12479, 1, '🧖 전기 발 마사지기 힐링 부츠형', '', '✨ 발등부터 발목까지 따뜻하게 감싸는 공기압 케어\n💎 분리형 세탁 커버로 항상 위생적인 관리 가능\n💰 고생하시는 부모님을 위한 프리미엄 선물 제안\n▶ 상세 보기', '', 1210000.00, 6050),
(12480, 1, '📸 4K 브이로그 카메라 미러리스', '', '✨ 셀카 촬영이 편리한 스위블 액정 탑재\n💎 초고화질 영상과 생생한 음성 녹음 기능\n🎁 촬영용 삼각대 및 메모리카드 풀패키지 증정\n▶ 구경하기', '', 600000.00, 3000),
(12481, 1, '💧 강력 제습기 12L 에너지 절약형', '', '✨ 눅눅한 실내 공기를 상쾌하게 바꿔주는 파워\n💎 물통 가득 참 알림 및 자동 정지 안전 기능\n💰 전기료 부담 없는 에너지 효율 등급 우수 상품\n▶ 쇼핑하기', '', 1890000.00, 9450),
(12482, 1, '🥗 저속 압착 주스기 원액기', '', '🍎 영양소 파괴 없이 채소와 과일 본연의 맛 그대로\n✨ 조용한 모터 소리로 아침에도 방해 없이 착즙\n📌 건강한 클렌즈 주스 만들기의 필수 가전\n▶ 제품 보기', '', 1280000.00, 6400),
(12483, 1, '⌨️ 블루투스 듀얼 모드 마우스', '', '✨ 클릭 소리 없이 조용한 무소음 설계\n💎 두 대의 기기를 버튼 하나로 간편하게 전환\n💰 사무용 필수템, 5가지 감각적인 컬러 출시\n▶ 구매하기', '', 670000.00, 3350),
(12484, 1, '🧴 펫 전용 자동 급식기 스마트형', '', '✨ 집 밖에서도 스마트폰으로 챙겨주는 반려동물 식사\n💎 신선도 유지를 위한 밀폐 구조와 제습제 탑재\n📌 목소리 녹음 기능으로 반려견의 안도감 형성\n▶ 더 보기', '', 1960000.00, 9800),
(12485, 1, '⌚ 스마트워치 스포츠 에디션 밴드', '', '🏃 초경량 무게로 운동 시 착용감을 최소화\n✨ 수영 중에도 사용 가능한 완벽 방수 지원\n💰 스포츠 전문 밴드 추가 증정 프로모션 진행\n▶ 바로가기', '', 1350000.00, 6750),
(12486, 1, '🍲 멀티 전기 냄비 투인원 분리형', '', '🔥 전골 요리와 구이를 번갈아 가며 즐기세요\n✨ 코팅력이 우수해 세척이 간편한 분리형 팬\n📌 캠핑장이나 식탁 위 어디서든 훌륭한 주방장\n▶ 쇼핑하기', '', 740000.00, 3700),
(12487, 1, '🌬️ 타워 선풍기 안전망 일체형', '', '🍃 날개가 보이지 않아 아이나 반려동물 있는 집 추천\n✨ 세련된 타워 디자인으로 인테리어 포인트\n💰 시즌 오프 파격 할인 가격으로 미리 준비하세요\n▶ 제품 보기', '', 130000.00, 650),
(12488, 1, '🧊 가정용 급속 제빙기 실버 에디션', '', '❄️ 단 10분 만에 투명한 얼음을 만들어 드립니다\n✨ 물 부족 자동 알림 기능으로 편리한 사용\n💰 홈술족과 홈카페 매니아를 위한 필수 가전\n▶ 구매하기', '', 1420000.00, 7100),
(12489, 1, '🚿 자동 거품 비누 디스펜서 옐로우', '', '✨ 아이들이 좋아하는 귀여운 디자인과 컬러\n💎 비접촉 방식으로 위생적인 손 씻기 습관 형성\n🎁 1+1 세트 구매 시 전용 스티커 사은품 증정\n▶ 상세 보기', '', 810000.00, 4050),
(12490, 1, '🍞 와플 & 붕어빵 메이커 3in1', '', '✨ 주말 아침 우리 집을 카페로 바꾸는 마법\n💎 플레이트만 교체하면 샌드위치까지 뚝딱\n📌 자취생 및 주부들에게 인기 폭발 베스트셀러\n▶ 쇼핑하기', '', 200000.00, 1000),
(12491, 1, '🔌 스마트 AI 플러그 낱개 세트', '', '✨ 가전제품 소비 전력을 실시간으로 확인하세요\n💎 대기 전력을 완벽 차단하여 전기 요금 절약\n💰 스마트 홈 입문자를 위한 실속형 패키지\n▶ 구매하기', '', 1490000.00, 7450),
(12492, 1, '🏋️ 진동 마사지건 콤팩트 라이트', '', '✨ 작지만 강력한 진동! 가방에 넣고 다니는 힐링\n💎 운동 전후 근육 피로를 푸는 가장 스마트한 방법\n🎁 전용 보관 파우치 및 충전 케이블 포함\n▶ 제품 보기', '', 880000.00, 4400),
(12493, 1, '🥩 휴대용 인덕션 블랙 크리스탈', '', '🥩 높은 열효율로 빠르게 조리하는 프리미엄 인덕션\n✨ 슬림하고 견고한 상판으로 관리가 쉽습니다\n💰 한정 기간 전용 캐리 가방 무료 증정\n▶ 구경하기', '', 270000.00, 1350),
(12494, 1, '🧥 신발 살균 건조기 프로 듀얼', '', '👟 비에 젖은 운동화도 금방 뽀송하게 말려드려요\n✨ 강력한 살균 기능으로 발 건강까지 챙기세요\n📌 등산객이나 러닝족이 극찬한 필수 관리 가전\n▶ 구매하기', '', 1560000.00, 7800),
(12495, 1, '💨 탁상용 공기청정기 필터 교체형', '', '🍃 내 공부방이나 서재를 위한 개인용 청정기\n✨ 초미세먼지까지 걸러내는 헤파필터의 성능\n💰 런칭 기념 특가 세일 및 배송비 무료 혜택\n▶ 쇼핑하기', '', 950000.00, 4750),
(12496, 1, '🥛 전동 두유 제조기 간편형', '', '✨ 건강한 아침 식사를 위한 20분의 기적\n💎 불리지 않은 콩도 부드럽게 갈아주는 고성능 날\n📌 건강 관리를 시작하는 분께 선물로 추천\n▶ 제품 보기', '', 340000.00, 1700),
(12497, 1, '🧖 갈바닉 피부 마사지기 홈케어 세트', '', '✨ 미세 전류로 탄력 있고 맑은 피부 완성\n💎 집에서 관리하는 프리미엄 뷰티 디바이스\n💰 구매 시 전용 수분 젤 2개월분 추가 증정\n▶ 상세 보기', '', 1630000.00, 8150),
(12498, 1, '🧴 초음파 안경 세척기 블랙 에디션', '', '✨ 전문가의 손길처럼 안경 틈새까지 깨끗하게\n💎 주얼리, 시계, 면도날까지 세척 가능한 멀티형\n📌 스마트한 남자의 필수 생활 가전 아이템\n▶ 구매하기', '', 1020000.00, 5100),
(12499, 1, '🌡️ 온열 진동 눈 마사지기 폴딩형', '', '✨ 눈의 피로를 풀어주는 따스한 온기와 지압\n💎 반으로 접혀 휴대가 편리한 스마트 디자인\n💰 수험생과 직장인을 위한 힐링 선물 추천\n▶ 쇼핑하기', '', 410000.00, 2050),
(12500, 1, '🔋 캠핑용 대용량 파워뱅크 2000Wh', '', '📱 대가족 캠핑도 문제 없는 압도적 배터리 용량\n✨ 모든 캠핑 가전을 전력 걱정 없이 사용하세요\n💰 최신 모델 출시 기념 사은품 증정 프로모션\n▶ 제품 보기', '', 1700000.00, 8500);
